INSERT INTO tqc__rules VALUES(83,'A-1-1','IT system','BYD System Integration','Online',unistr('Markets in active integration rollout: Markets that, within the current cycle, are in any of the following stages: integration, development, testing, or go-live.\u000aMarkets in integration rollout preparation: Markets that have not started integration yet, but are already planned for a future rollout batch and are required to support plan finalization and prerequisite readiness activities.\u000a\u000aFor markets in active integration rollout, the score is prorated based on the completion status of the system development stages.\u000aFor markets in rollout preparation, the score is based on (1) the ability to finalize and lock the rollout plan and (2) completion of prerequisite readiness items.'),60,1,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('For the market in active integration rollout, the total score is 50 points:\u000aAttitude assessment:\u000aDistributor promptly responds to BYD''s message within 3 working days, give 10 scores.\u000aCompletion stage:\u000aEntering the development phase, give 20 scores;\u000aUpon completing system development and entering the testing phase, give 30 scores;\u000aTest completed and officially launching on schedule, give 40 scores.\u000a\u000aFor market in integration rollout preparation, the total score is 50 points:\u000aAttitude assessment:\u000aDistributor promptly responds to BYD''s message within 3 working days, give 10 scores.\u000aCompletion stage:\u000aProvide and confirm the timeline and deadline, responsible person, and resource arrangement, each item will be given 10 score, and the total scores is 30;\u000aComplete the test environment configuration, give 10 score.'),'比亚迪系统集成','Integración del sistema BYD',unistr('积极集成推出的市场：在当前周期内处于以下任一阶段的市场：集成、开发、测试或上线。\u000a正在准备整合推出的市场：尚未开始整合，但已计划未来批量推出，并需要支持计划最终确定和先决条件准备活动的市场。\u000a\u000a对于积极集成推出的市场，分数根据系统开发阶段的完成状态按比例分配。\u000a对于处于推出准备阶段的市场，分数基于 (1) 最终确定和锁定推出计划的能力以及 (2) 必备准备项目的完成情况。'),unistr('Mercados en implementación activa de integración: Mercados que, dentro del ciclo actual, se encuentran en cualquiera de las siguientes etapas: integración, desarrollo, pruebas o puesta en marcha.\u000aMercados en preparación para el lanzamiento de la integración: Mercados que aún no han comenzado la integración, pero que ya están planificados para un lote de lanzamiento futuro y deben respaldar la finalización del plan y las actividades de preparación de requisitos previos.\u000a\u000aPara los mercados en implementación de integración activa, la puntuación se prorratea en función del estado de finalización de las etapas de desarrollo del sistema.\u000aPara los mercados en preparación de implementación, la puntuación se basa en (1) la capacidad de finalizar y bloquear el plan de implementación y (2) la finalización de los requisitos previos de preparación.'),unistr('对于主动整合的市场，总分为50分：\u000a态度评估：\u000a经销商在3个工作日内及时回复比亚迪消息，给予10分。\u000a完成阶段：\u000a进入开发阶段，给20分；\u000a系统开发完成并进入测试阶段，打30分；\u000a测试如期完成并正式启动，给40分。\u000a\u000a对于整合推出准备市场，总分为50分：\u000a态度评估：\u000a经销商在3个工作日内及时回复比亚迪消息，给予10分。\u000a完成阶段：\u000a提供并确认时间表和期限、负责人、资源安排，每项打10分，总分为30分；\u000a完成测试环境配置，给10分。'),unistr('Para el mercado en implementación de integración activa, la puntuación total es de 50 puntos:\u000aEvaluación de actitud:\u000aEl distribuidor responde rápidamente al mensaje de BYD dentro de los 3 días hábiles y otorga 10 puntajes.\u000aEtapa de finalización:\u000aAl ingresar a la fase de desarrollo, otorgue 20 puntajes;\u000aAl completar el desarrollo del sistema y entrar en la fase de prueba, otorgue 30 puntajes;\u000aPrueba completada y lanzada oficialmente según lo previsto, obtenga 40 puntuaciones.\u000a\u000aPara la preparación del lanzamiento de la integración en el mercado, la puntuación total es de 50 puntos:\u000aEvaluación de actitud:\u000aEl distribuidor responde rápidamente al mensaje de BYD dentro de los 3 días hábiles y otorga 10 puntajes.\u000aEtapa de finalización:\u000aProporcione y confirme el cronograma y la fecha límite, la persona responsable y la disposición de recursos; cada elemento recibirá una puntuación de 10 y la puntuación total será 30;\u000aComplete la configuración del entorno de prueba y otorgue una puntuación de 10.'),'信息技术系统','sistema de TI',NULL);
INSERT INTO tqc__rules VALUES(84,'A-1-2','IT system','DMS work order Input','Online',unistr('Check whether the dealer has accurately entered the work order information into the BYD DMS system as required. The following fields must be included:\u000a- VIN\u000a- Repair shop code\u000a- Repair shop name\u000a- Total mileage\u000a- Work order type\u000a- Repair type\u000a- Opening date: Namely dispatch time, time should be accurate to the minute\u000a- Settlement time: Namely completion time, time should be accurate to the minute\u000a- Repair labor hour\u000a- Repair materials\u000a- Settlement amount: namely total amount'),30,2,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If 90% of the work order are 100% complete in field content, and the values in these fields are not empty, with no errors in timing or logic, give 30 scores;\u000aIf any item does not meet the requirements, give 0 score.'),'DMS工单输入','Entrada de orden de trabajo de DMS',unistr('检查经销商是否按照要求准确地将工单信息录入比亚迪DMS系统。必须包含以下字段：\u000a- 车架号\u000a- 维修店代码\u000a- 维修店名称\u000a- 总里程\u000a- 工单类型\u000a- 维修类型\u000a- 开放日期：即发货时间，时间要精确到分钟\u000a- 结算时间：即完成时间，时间应精确到分钟\u000a- 维修工时\u000a- 修复材料\u000a- 结算金额：即总额'),unistr('Verifique si el distribuidor ha ingresado con precisión la información de la orden de trabajo en el sistema BYD DMS según sea necesario. Se deben incluir los siguientes campos:\u000a-VIN\u000a- Código de taller de reparación\u000a- Nombre del taller de reparación\u000a- Kilometraje total\u000a- Tipo de orden de trabajo\u000a- Tipo de reparación\u000a- Fecha de apertura: es decir, hora de envío, la hora debe ser exacta al minuto.\u000a- Tiempo de liquidación: es decir, tiempo de finalización, el tiempo debe ser exacto al minuto.\u000a- Hora de mano de obra de reparación.\u000a- Materiales de reparación\u000a- Importe de la liquidación: es decir, importe total'),unistr('如果90%的工单在字段内容上100%完成，并且这些字段中的值不为空，在时序或逻辑上没有错误，则给30分；\u000a若有任何一项不符合要求，则给0分。'),unistr('Si el 90 % de la orden de trabajo está 100 % completo en el contenido de los campos y los valores en estos campos no están vacíos, sin errores de tiempo o lógica, otorgue 30 puntajes;\u000aSi algún ítem no cumple con los requisitos, otorgue 0 puntaje.'),'信息技术系统','sistema de TI',NULL);
INSERT INTO tqc__rules VALUES(85,'A-1-3','IT system','TIS Use','Online',unistr('Count the login situations of system accounts on monthly basis. Calculate the number of accounts that have not logged in continuously for 2 months, and compute the account usage rate:\u000aThe account usage rate = (total number of accounts - number of accounts that haven''t logged in continuously for 2 months) /total number of accounts × 100%'),5,3,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If it is greater than 90%, give 5 scores; otherwise, give 0 score.','TIS 使用','Uso de TIS',unistr('每月统计系统账号的登录情况。计算连续2个月未登录的账户数，并计算账户使用率：\u000a账户使用率=（账户总数-连续2个月未登录的账户数）/账户总数×100%'),unistr('Cuente las situaciones de inicio de sesión de las cuentas del sistema mensualmente. Calcule la cantidad de cuentas que no han iniciado sesión continuamente durante 2 meses y calcule la tasa de uso de la cuenta:\u000aLa tasa de uso de la cuenta = (número total de cuentas - número de cuentas que no han iniciado sesión continuamente durante 2 meses) /número total de cuentas × 100%'),'如果大于90%，给5分；否则，给0分。','Si es mayor al 90%, dé 5 puntajes; de lo contrario, dé 0 puntuación.','信息技术系统','sistema de TI',NULL);
INSERT INTO tqc__rules VALUES(86,'A-1-4','IT system','TIS Use','Online','Check whether the TIS system service store account has TIS technical consultation or spare parts Q&A records.',5,4,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If TIS system service store account has TIS technical consultation or spare parts Q&A records, give 5 scores;\u000aOtherwise, give 0 score.'),'TIS 使用','Uso de TIS','检查TIS系统服务店账号是否有TIS技术咨询或备件问答记录。','Verifique si la cuenta de la tienda de servicios del sistema TIS tiene consultas técnicas de TIS o registros de preguntas y respuestas sobre repuestos.',unistr('若TIS系统服务店账号有TIS技术咨询或备件问答记录，则给5分；\u000a否则，给0分。'),unistr('Si la cuenta de la tienda de servicios del sistema TIS tiene consultas técnicas de TIS o registros de preguntas y respuestas sobre repuestos, otorgue 5 puntajes;\u000aDe lo contrario, dé 0 puntos.'),'信息技术系统','sistema de TI',NULL);
INSERT INTO tqc__rules VALUES(87,'A-1-5','IT system','TIS Use','Online',unistr('Check the LMS system account activation rate of all personnel of distributor and its service stores within the assessment period. “Account activation” means the account has completed its first login.\u000aAccount Activation Rate = Number of activated accounts/ Total number of registered accounts'),5,5,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. If the account activation rate is [90%, 100%], give 5 scores.\u000a2. If the account activation rate is [80%, 90%), give 3 scores.\u000a3. If the account activation rate is [0%, 80%), give 0 scores.'),'TIS 使用','Uso de TIS',unistr('检查考核期内经销商及其服务店所有人员的LMS系统账号激活率。 “账户激活”是指账户已完成首次登录。\u000a账户激活率=激活账户数/注册账户总数'),unistr('Verificar la tasa de activación de cuentas del sistema LMS de todo el personal del distribuidor y sus tiendas de servicio dentro del período de evaluación. "Activación de cuenta" significa que la cuenta ha completado su primer inicio de sesión.\u000aTasa de activación de cuentas = Número de cuentas activadas/Número total de cuentas registradas'),unistr('1、如果账号激活率为[90%, 100%]，则给5分。\u000a2、如果账号激活率为[80%, 90%)，则给3分。\u000a3、如果账户激活率为[0%, 80%)，则给0分。'),unistr('1. Si la tasa de activación de la cuenta es [90%, 100%], otorgue 5 puntajes.\u000a2. Si la tasa de activación de la cuenta es [80%, 90%), dé 3 puntuaciones.\u000a3. Si la tasa de activación de la cuenta es [0%, 80%), dé 0 puntos.'),'信息技术系统','sistema de TI',NULL);
INSERT INTO tqc__rules VALUES(88,'A-2-1','Warranty Claim Management','One-Time Pass Rate','Online',unistr('Check the one time pass rate of the store''s warranty claim work order during the assessment period.\u000aOne time pass rate=qty of warranty claim work orders which pass inpection in only one time/all warranty claim work orders reviewed by BYD*100%'),25,6,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. One Time Pass Rate is 100%, give 25 scores;\u000a2. One Time Pass Rate is [95%, 100%), give 20 scores;\u000a3. One Time Pass Rate is [80%, 95%), give 15 scores;\u000a4. One Time Pass Rate is [0%, 80%), give 0 score.'),'一次性通过率','Tarifa de pase único',unistr('检查考核期内门店保修索赔工单一次性合格率。\u000a一次性合格率=仅一次检验合格的保修工单数量/比亚迪审核的所有保修工单*100%'),unistr('Verifique la tasa de aprobación única de la orden de trabajo de reclamo de garantía de la tienda durante el período de evaluación.\u000aTasa de aprobación única = cantidad de órdenes de trabajo de reclamo de garantía que pasan la inspección solo una vez/todas las órdenes de trabajo de reclamo de garantía revisadas por BYD*100%'),unistr('1、一次性通过率为100%，评分为25分；\u000a2. 一次性通过率为[95%, 100%)，给20分；\u000a3. 一次性通过率为[80%, 95%)，给15分；\u000a4. 一次性通过率为[0%, 80%)，给0分。'),unistr('1. La tasa de aprobación única es del 100%, otorga 25 puntajes;\u000a2. La tasa de aprobación única es [95%, 100%), otorga 20 puntajes;\u000a3. La tasa de aprobación única es [80%, 95%), otorga 15 puntajes;\u000a4. La tasa de aprobación única es [0%, 80%), otorga 0 puntuación.'),'保修索赔管理','Gestión de reclamaciones de garantía',NULL);
INSERT INTO tqc__rules VALUES(89,'A-2-2','Warranty Claim Management','Timely Submission Rate','Online',unistr('Check the timely submission rate of the store''s warranty claim work order during the TQC period. Distributors should submit warranty claim work order within 15 natural days since they submit the settlement work order in DMS.\u000aTimely submission rate=qty of warranty claim work orders which have been timely submitted/all warranty claim work orders which have been submitted*100%'),25,7,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Timely Submission Rate is [95%, 100%], give 25 scores;\u000a2. Timely Submission Rate is [90%, 95%), give 20 scores;\u000a3. Timely Submission Rate is [80%, 90%), give 15 scores;\u000a4. Timely Submission Rate is [0%, 80%), give 0 score.'),'及时提交率','Tasa de envío oportuno',unistr('检查TQC期间门店保修索赔工单的及时提交率。经销商应在DMS提交结算工单后15个自然日内提交保修索赔工单。\u000a及时提交率=及时提交的保修索赔工单数量/所有已提交的保修索赔工单*100%'),unistr('Verifique la tasa de envío oportuno de la orden de trabajo de reclamo de garantía de la tienda durante el período de TQC. Los distribuidores deben presentar la orden de trabajo de reclamo de garantía dentro de los 15 días naturales desde que envían la orden de trabajo de liquidación en DMS.\u000aTasa de envío oportuno=cantidad de órdenes de trabajo de reclamos de garantía que se enviaron oportunamente/todas las órdenes de trabajo de reclamos de garantía que se enviaron*100%'),unistr('1.及时提交率为[95%,100%]，给25分；\u000a2.及时提交率为[90%, 95%)，给20分；\u000a3、及时提交率为[80%, 90%)，给15分；\u000a4.及时提交率为[0%, 80%)，给0分。'),unistr('1. La tasa de envío oportuno es [95%, 100%], otorgue 25 puntajes;\u000a2. La tasa de envío oportuno es [90%, 95%), otorga 20 puntajes;\u000a3. La tasa de envío oportuno es [80%, 90%), otorga 15 puntajes;\u000a4. La tasa de envío oportuno es [0%, 80%), otorga 0 puntuación.'),'保修索赔管理','Gestión de reclamaciones de garantía',NULL);
INSERT INTO tqc__rules VALUES(90,'A-3-1','Training Management','Online Training','Online',unistr('Check the signing up of online training courses of distributors and their service stores during the TQC inspection period:\u000aa. The number of people signing up the same course≥3；\u000ab. Signing up timely and giving feedback to BYD timely for each course.'),5,8,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. If meet the requirement of both a & b, give 5 scores;\u000a2. If only meet the requirement of both a or b, give 3 scores;\u000a3. If don''t meet the requirement of a or b, give 0 scores.'),'在线培训','Capacitación en línea',unistr('检查TQC检验期间经销商及其服务店在线培训课程报名情况：\u000aa.同一课程报名人数≥3人；\u000ab.每门课程及时报名并及时向比亚迪反馈。'),unistr('Consulta la inscripción a cursos de capacitación en línea de distribuidores y sus tiendas de servicio durante el período de inspección TQC:\u000aun. El número de personas inscritas en el mismo curso≥3；\u000aB. Registrarse oportunamente y brindar comentarios a BYD oportunamente para cada curso.'),unistr('1、如果a、b同时满足，则打5分；\u000a2、若仅满足a或b的要求，则打3分；\u000a3. 如果不满足a或b的要求，则给0分。'),unistr('1. Si cumple con los requisitos de a y b, otorgue 5 puntajes;\u000a2. Si solo cumple con el requisito de aob, otorgue 3 puntajes;\u000a3. Si no cumple con el requisito de aob, otorgue 0 puntajes.'),'培训管理','Gestión de la formación',NULL);
INSERT INTO tqc__rules VALUES(91,'A-3-2','Training Management','Online Training','Online',unistr('Check the attendance rate for online training during the TQC period:\u000aAttendance rate = number of people who have attended all the courses/ number of people signing up in one course*100%.'),5,9,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Attendance rate is [80%, 100%], give 5 scores;\u000a2. Attendance rate is [50%, 80%), give 3 scores;\u000a3. Attendance rate is [0%, 50%), give 0 score.'),'在线培训','Capacitación en línea',unistr('查看TQC期间在线培训的出勤率：\u000a出席率=参加所有课程的人数/一门课程报名人数*100%。'),unistr('Consulta el índice de asistencia a la formación online durante el periodo TQC:\u000aTasa de asistencia = número de personas que han asistido a todos los cursos/ número de personas inscritas en un curso*100%.'),unistr('1. 出勤率为[80%, 100%]，给5分；\u000a2. 出勤率为[50%, 80%)，给3分；\u000a3. 出勤率为[0%, 50%)，给0分。'),unistr('1. La tasa de asistencia es [80%, 100%], dé 5 puntajes;\u000a2. La tasa de asistencia es [50%, 80%), dé 3 puntajes;\u000a3. La tasa de asistencia es [0%, 50%), dé 0 puntuación.'),'培训管理','Gestión de la formación',NULL);
INSERT INTO tqc__rules VALUES(92,'A-3-3','Training Management','Online Training','Online',unistr('Check the pass rate of corresponding online training: if one course gets ≥80 score, this course is regarded PASS.\u000aPass rate = Number of people who have passed all the course during the assessment period/ Number of people who attend the training*100%.'),5,10,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Attendance rate is [80%, 100%], give 5 scores;\u000a2. Attendance rate is [50%, 80%), give 3 scores;\u000a3. Attendance rate is [0%, 50%), give 0 score.'),'在线培训','Capacitación en línea',unistr('查看相应在线培训的通过率：如果一门课程得分≥80分，则该课程视为PASS。\u000a通过率=考核期内全部课程通过的人数/参加培训的人数*100%。'),unistr('Verifique la tasa de aprobación de la capacitación en línea correspondiente: si un curso obtiene una puntuación ≥80, este curso se considera APROBADO.\u000aTasa de aprobación = Número de personas que han aprobado todo el curso durante el periodo de evaluación/ Número de personas que asisten a la formación*100%.'),unistr('1. 出勤率为[80%, 100%]，给5分；\u000a2. 出勤率为[50%, 80%)，给3分；\u000a3. 出勤率为[0%, 50%)，给0分。'),unistr('1. La tasa de asistencia es [80%, 100%], dé 5 puntajes;\u000a2. La tasa de asistencia es [50%, 80%), dé 3 puntajes;\u000a3. La tasa de asistencia es [0%, 50%), dé 0 puntuación.'),'培训管理','Gestión de la formación',NULL);
INSERT INTO tqc__rules VALUES(93,'A-3-4','Training Management','Training Certification','Online',unistr('Check whether the technicians (both of distributors and service stores, including the workshop supervisors and technicians) recorded in LMS have passed the primary technician certification.\u000aPrimary technician certification rate= The accounts in LMS which get primary technician certificationin/ All the LMS accounts of technicians in workshop*100%'),10,11,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Completion rate is [95%, 100%], give 10 scores;\u000a2. Completion rate is [80%, 95%), give 5 scores;\u000a3. Completion rate is [0%, 80%), give 0 score.'),'培训认证','Certificación de formación',unistr('检查LMS中记录的技术人员（经销商和服务店，包括车间主管和技术人员）是否通过初级技术人员认证。\u000a初级技术人员认证率=LMS中获得初级技术人员认证的账户数/车间所有技术人员的LMS账户数*100%'),unistr('Compruebe si los técnicos (tanto de distribuidores como de tiendas de servicio, incluidos los supervisores de taller y técnicos) registrados en LMS han superado la certificación de técnico primario.\u000aTasa de certificación de técnico primario = Las cuentas en LMS que obtienen la certificación de técnico primario en/ Todas las cuentas de LMS de los técnicos en el taller*100%'),unistr('1.完成率为[95%,100%]，给10分；\u000a2.完成率为[80%,95%)，给5分；\u000a3. 完成率为[0%, 80%)，给0分。'),unistr('1. La tasa de finalización es [95%, 100%], dé 10 puntos;\u000a2. La tasa de finalización es [80%, 95%), dé 5 puntuaciones;\u000a3. La tasa de finalización es [0%, 80%), otorga 0 puntuación.'),'培训管理','Gestión de la formación',NULL);
INSERT INTO tqc__rules VALUES(94,'A-3-5','Training Management','Training Certification','Online',unistr('Number of service advisor certification pass rate through internal training,\u000aRate=Number of service advisor who have passed the certification during the assessment period / Total number of service consultants during the assessment period'),10,12,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('The service consultant certification pass rate is [90%, 100%], give 10 scores;\u000aThe service consultant certification pass rate is [80%, 90%), give 5 scores;\u000aThe service consultant certification pass rate is [0%, 80%), give 0 score.'),'培训认证','Certificación de formación',unistr('通过内部培训的服务顾问认证通过率，\u000a比例=考核期内通过认证的服务顾问人数/考核期内服务顾问总数'),unistr('Número de tasas de aprobación de la certificación de asesor de servicio a través de capacitación interna.\u000aTasa=Número de asesores de servicio que aprobaron la certificación durante el período de evaluación / Número total de consultores de servicio durante el período de evaluación'),unistr('服务顾问认证通过率为[90%、100%]，给10分；\u000a服务顾问认证通过率为[80%,90%)，给5分；\u000a服务顾问认证通过率为[0%, 80%)，给0分。'),unistr('La tasa de aprobación de la certificación de consultor de servicios es [90%, 100%], otorgue 10 puntajes;\u000aLa tasa de aprobación de la certificación de consultor de servicios es [80%, 90%), otorga 5 puntajes;\u000aLa tasa de aprobación de la certificación de consultor de servicios es [0%, 80%), otorga 0 puntuación.'),'培训管理','Gestión de la formación',NULL);
INSERT INTO tqc__rules VALUES(95,'A-3-6','Training Management','Internal Training Execution','Online','Check whether distributor has submitted internal trainning plan for this month and internal trainning record for last month to BYD before 10th this month, and check whether the record is completed.',10,13,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If submited timely and record is completed, give 5 scores; Not timely submitted or record is not completed, give 0 score.','内部培训执行','Ejecución de Capacitación Interna','检查经销商是否于本月10日前向比亚迪提交本月内部培训计划和上个月内部培训记录，并检查记录是否完​​成。','Verifique si el distribuidor ha enviado el plan de capacitación interna para este mes y el registro de capacitación interna del mes pasado a BYD antes del día 10 de este mes, y verifique si el registro está completo.','如果及时提交并记录完成，给5分；未及时提交或记录未完成，给0分。','Si se presenta a tiempo y se completa el registro, dé 5 puntajes; No enviado a tiempo o el registro no está completo, otorgue 0 puntaje.','培训管理','Gestión de la formación',NULL);
INSERT INTO tqc__rules VALUES(96,'A-3-7','Training Management','Internal Training Execution','Online','Check whether the monthly internal trainning provided by distributors accord with BYD''s requirements: monthly trainning time should be ≥12 hours, attendors in each course should be ≥5.',15,14,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('Monthly training time≥12 hours, attendors ≥5 for each course, give 10 scores;\u000aIf not meet the requirement, give 0 score;'),'内部培训执行','Ejecución de Capacitación Interna','检查经销商提供的每月内部培训是否符合比亚迪的要求：每月培训时间≥12小时，每次课程参加人数≥5人。','Verifique si la capacitación interna mensual brindada por los distribuidores cumple con los requisitos de BYD: el tiempo de capacitación mensual debe ser ≥12 horas, los asistentes a cada curso deben ser ≥5.',unistr('每月培训时间≥12小时，每门课程参加人数≥5人，打10分；\u000a若不满足要求，则给0分；'),unistr('Tiempo de capacitación mensual ≥12 horas, asistentes ≥5 por cada curso, otorga 10 puntajes;\u000aSi no cumple con el requisito, otorgue 0 puntaje;'),'培训管理','Gestión de la formación',NULL);
INSERT INTO tqc__rules VALUES(97,'A-3-8','Training Management','Internal Training Execution','Online','Verify whether the agent has conducted internal training in accordance with the training plan each month during the assessment period;',15,15,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('Conducted internal training in accordance with the training plan each month, give 10 scores;\u000afailing to implement the plan and not submitting a plan change application, give 0 score;'),'内部培训执行','Ejecución de Capacitación Interna','考核期间每月核实代理商是否按照培训计划进行了内部培训；','Verificar si el agente ha realizado capacitación interna de acuerdo con el plan de capacitación cada mes durante el período de evaluación;',unistr('每月按照培训计划进行内部培训，给予10分；\u000a未落实计划且未提交计划变更申请的，计0分；'),unistr('Realicé capacitación interna de acuerdo con el plan de capacitación cada mes, otorgue 10 puntajes;\u000ano implementar el plan y no presentar una solicitud de cambio de plan, otorgar 0 puntaje;'),'培训管理','Gestión de la formación',NULL);
INSERT INTO tqc__rules VALUES(98,'A-4-1','Spare Parts Management','Reserve of Regularly Prepared Spare Parts','Online',unistr('Check the overall reserve rate of a distributor\u000avehicle model: TOP3 models in terms of holdings spare parts type: A+B.\u000aThe comparison data comes from the TOP3 model A+B spare part list which generated at the end of last month in the quarter.\u000aThe service store should provide the Spare Parts Inventory Enquiry in DMS.'),40,16,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('Threshold Requirement: The service store should use Spare Parts Inventory Enquiry Function in DMS, and update the enquiry result in DMS.\u000a1. Reserve rate is [90%, 100%], give 40 scores.\u000a2. Reserve rate is [75%, 90%), give 30 scores.\u000a3. Reserve rate is [60%, 75%), give 20 scores.\u000a4. Reserve rate is [0, 60%), give 0 score.'),'定期备件储备','Reserva de repuestos preparados periódicamente',unistr('查看经销商整体准备金率\u000a车型：保有备件类型TOP3车型：A+B。\u000a对比数据来自本季度上月底生成的TOP3型号A+B备件清单。\u000a服务店应在DMS中提供备件库存查询。'),unistr('Consultar la tasa de reserva global de un distribuidor\u000aModelo de vehículo: TOP3 modelos en cuanto a existencias de recambios tipo: A+B.\u000aLos datos de comparación provienen de la lista de repuestos del modelo A+B TOP3 que se generó a finales del mes pasado en el trimestre.\u000aLa tienda de servicios debe proporcionar la Consulta de inventario de repuestos en DMS.'),unistr('门槛要求：服务店应使用DMS中的备件库存查询功能，并更新DMS中的查询结果。\u000a1、保留率为[90%,100%]，给40分。\u000a2. 保留率[75%, 90%)，给30分。\u000a3. 保留率[60%, 75%)，给20分。\u000a4. 储备率为[0, 60%)，给0分。'),unistr('Requisito de umbral: la tienda de servicios debe utilizar la función de consulta de inventario de repuestos en DMS y actualizar el resultado de la consulta en DMS.\u000a1. La tasa de reserva es [90%, 100%], dé 40 puntajes.\u000a2. La tasa de reserva es [75%, 90%), dé 30 puntajes.\u000a3. La tasa de reserva es [60%, 75%), dé 20 puntajes.\u000a4. La tasa de reserva es [0, 60%), otorga 0 puntuación.'),'备件管理','Gestión de repuestos',NULL);
INSERT INTO tqc__rules VALUES(99,'A-4-2','Spare Parts Management','Service Spare Parts Fulfillment Rate','Online',unistr('Check the service spare parts fulfillment rate in each service store.\u000aData source:\u000aAt the end of the assessment period, regional managers will collect information on whether each service store prepared enough spare parts for daily service.\u000aDuring the inspection period, Service Spare Parts Fulfillment Rate= The qty of spare part types that meet the service need in service stores/ The qty of spare part types that service stores purchased from distributors.'),40,17,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. service spare parts fulfillment rate is [90%, 100%], give 40 scores.\u000a2. service spare parts fulfillment rate is [75%, 90%), give 30 scores.\u000a3. service spare parts fulfillment rate is [60%, 75%), give 20 scores.\u000a4. service spare parts fulfillment rate is [0%, 60%), give 0 score.'),'服务备件履行率','Tasa de cumplimiento de repuestos de servicio',unistr('检查各服务店的服务备件履行率。\u000a数据来源：\u000a评估期结束时，区域经理将收集各服务店是否为日常服务准备了足够的备件的信息。\u000a检查期间，服务备件到位率=服务店满足服务需要的备件种类数量/服务店从经销商处采购的备件种类数量。'),unistr('Consulta el índice de cumplimiento de repuestos de servicio en cada tienda de servicio.\u000aFuente de datos:\u000aAl final del período de evaluación, los gerentes regionales recopilarán información sobre si cada tienda de servicio preparó suficientes repuestos para el servicio diario.\u000aDurante el período de inspección, Tasa de cumplimiento de repuestos de servicio = La cantidad de tipos de repuestos que satisfacen la necesidad de servicio en las tiendas de servicio/La cantidad de tipos de repuestos que las tiendas de servicio compraron a los distribuidores.'),unistr('1.服务备件履行率为[90%、100%]，给40分。\u000a2.服务备件履行率为[75%、90%)，给30分。\u000a3.服务备件履行率为[60%、75%)，给20分。\u000a4. 服务备件履行率为[0%, 60%)，给0分。'),unistr('1. La tasa de cumplimiento del servicio de repuestos es [90%, 100%], otorgue 40 puntajes.\u000a2. La tasa de cumplimiento del servicio de repuestos es [75%, 90%), otorga 30 puntajes.\u000a3. La tasa de cumplimiento del servicio de repuestos es [60%, 75%), otorga 20 puntajes.\u000a4. La tasa de cumplimiento del servicio de repuestos es [0%, 60%), otorga 0 puntuación.'),'备件管理','Gestión de repuestos',NULL);
INSERT INTO tqc__rules VALUES(100,'E-1','Spare Parts Management','Pre-payment of Spare Parts Account','Online',unistr('At the end of the assessment period, check whether the monthly balance of a distributor''s spare parts account is higher than 50% of the average order amount of spare parts orders in the two quarters before the assessment period.\u000aExample: At the end of the Q1 assessment period in 2025, the balance of the spare parts account should ≥50% the monthly average order amount of spare parts orders from Q3 to Q4 of 2024.'),25,18,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If balance in the account meets the requirement, give 25 scores; if doesn''t meet the requirement, give 0 score.','备件账户预付款','Cuenta Prepago de Repuestos',unistr('考核期结束时，检查经销商备件账户月余额是否高于考核期前两个季度备件订单平均订单额的50%。\u000a例：2025年第一季度考核期末，备件账户余额应≥2024年第三季度至第四季度备件订单月平均订单金额的50%。'),unistr('Al final del período de evaluación, verifique si el saldo mensual de la cuenta de repuestos de un distribuidor es superior al 50% del monto promedio de los pedidos de repuestos en los dos trimestres anteriores al período de evaluación.\u000aEjemplo: Al final del período de evaluación del primer trimestre de 2025, el saldo de la cuenta de repuestos debe ser ≥50% del monto promedio mensual de los pedidos de repuestos del tercer al cuarto trimestre de 2024.'),'如果账户余额符合要求，打25分；如果不符合要求，则给0分。','Si el saldo de la cuenta cumple con el requisito, dé 25 puntos; si no cumple con el requisito, otorgue 0 puntaje.','备件管理','Gestión de repuestos',NULL);
INSERT INTO tqc__rules VALUES(101,'E-2','Spare Parts Management','Timeliness of spare parts ordering for newly launched models','Online',unistr('1.Assess whether spare parts are ordered in time before the launch of new models in the agent market\u000a2.Assessment requirements: at the end of each quarter, assess whether the agent places an order and pays (provide the bank slip) for the newly launched models within 3 weeks after receiving the list of spare parts for the first batch of vehicles'),25,19,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1.If there is new launched model and place the order within 1 week after receiving the spare list, give 25 scores；\u000a2.If there is new launched model and place the order within 2 weeks after receiving the spare list, give 15scores；\u000a3.If there is new launched model and place the order within 3 weeks after receiving the spare list, give 10 scores；\u000a4.If no new new model or place the order after exceeding 3 weeks, give 0 score.'),'新上市车型备件订购及时性','Puntualidad en el pedido de repuestos para modelos recién lanzados.',unistr('1.在代理市场新车型上市前评估备件是否及时订购\u000a2.评估要求：每季度末，评估代理商在收到首批车辆备件清单后3周内是否对新上市车型下单并付款（提供银行水单）'),unistr('1.Evaluar si los repuestos se solicitan a tiempo antes del lanzamiento de nuevos modelos en el mercado de agentes.\u000a2.Requisitos de evaluación: al final de cada trimestre, evaluar si el agente realiza un pedido y paga (proporciona el comprobante bancario) los modelos recién lanzados dentro de las 3 semanas posteriores a la recepción de la lista de repuestos para el primer lote de vehículos.'),unistr('1.如果有新推出的型号，并在收到备件清单后1周内下单，给25分；\u000a2.如果有新推出的型号，并在收到备件清单后2周内下单，给15分；\u000a3.如果有新推出的型号，并在收到备件清单后3周内下单，给10分；\u000a4.如果没有新型号或超过3周后下订单，则给0分。'),unistr('1. Si hay un nuevo modelo lanzado y realiza el pedido dentro de 1 semana después de recibir la lista de repuestos, otorgue 25 puntajes;\u000a2. Si hay un nuevo modelo lanzado y realiza el pedido dentro de las 2 semanas posteriores a recibir la lista de repuestos, proporcione 15 puntuaciones;\u000a3. Si hay un nuevo modelo lanzado y realiza el pedido dentro de las 3 semanas posteriores a la recepción de la lista de repuestos, otorgue 10 puntajes;\u000a4. Si no hay ningún modelo nuevo o realiza el pedido después de exceder las 3 semanas, otorgue 0 puntaje.'),'备件管理','Gestión de repuestos',NULL);
INSERT INTO tqc__rules VALUES(102,'A-4-3','Spare Parts Management','After-sales Technician Uniform Purchase','Online',unistr('Check whether distributors place orders in the DMS as required.\u000aUniform allocation standard: based on the number of technicians:\u000a– Short-sleeve polo shirts: 3 pcs / technician\u000a– Black pants: 3 pcs / technician\u000a– Jacket: 1 pc / technician\u000a– Coveralls: 3 pcs / technician'),20,20,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','Compliant ordering: 30 points; non-compliant: 0 points.','售后技术员制服购买','Compra de Uniforme de Técnico Postventa',unistr('检查经销商是否按要求在DMS下单。\u000a统一分配标准：根据技术人员数量：\u000a– 短袖 Polo 衫：3 件/技术员\u000a– 黑色裤子：3 件/技术员\u000a– 夹克：1 件/技术员\u000a– 工作服：3 件/技术员'),unistr('Compruebe si los distribuidores realizan pedidos en el DMS según sea necesario.\u000aEstándar de asignación uniforme: en función del número de técnicos:\u000a– Polos de manga corta: 3 piezas/técnico\u000a– Pantalón negro: 3 piezas/técnico\u000a– Chaqueta: 1 ud/técnico\u000a– Monos: 3 piezas/técnico'),'合规订购：30分；不符合：0分。','Pedido conforme: 30 puntos; no conforme: 0 puntos.','备件管理','Gestión de repuestos',NULL);
INSERT INTO tqc__rules VALUES(103,'A-5-1','Customer Service','24-hour Response Rate','Online','Check customer emails (inquiries, complaints, etc.) for the first response rate within 24 hours.',30,21,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If it meet the requirement, give 30 scores;\u000aIf not, give 0 score.\u000aNote: If there are no customer complaint emails within the assessment period, the score will be determined based on 70% of the total score.'),'24小时响应率','Tasa de respuesta en 24 horas','检查客户电子邮件（查询、投诉等），了解 24 小时内的首次回复率。','Consulte los correos electrónicos de los clientes (consultas, quejas, etc.) para conocer la tasa de primera respuesta dentro de las 24 horas.',unistr('如果符合要求，打30分；\u000a如果没有，给0分。\u000a注：若考核期内无客户投诉邮件，则按总分的70%确定分数。'),unistr('Si cumple con el requisito, otorgue 30 puntajes;\u000aEn caso contrario, dé 0 puntos.\u000aNota: Si no hay correos electrónicos de quejas de clientes dentro del período de evaluación, la puntuación se determinará en base al 70% de la puntuación total.'),'客户服务','Servicio al cliente',NULL);
INSERT INTO tqc__rules VALUES(104,'A-5-2','Customer Service','3-day Resolution Rate','Online','Check customer emails (inquiries, complaints, etc.) for resolution rate within 3 working days.',30,22,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('Check customer service emails (inquiries, complaints, etc.) for resolution rate within 3 working days.\u000a1. Resolution rate is [85, 100], give 30 scores.\u000a2. Resolution rate is [70, 85), give 15 scores.\u000a3. Resolution rate is [0, 70), give 0 score.\u000aNote: If there are no customer complaint emails within the assessment period, the score will be determined based on 70% of the total score.'),'3 天解决率','Tarifa de resolución de 3 días','检查客户电子邮件（查询、投诉等），了解 3 个工作日内的解决率。','Consulte los correos electrónicos de los clientes (consultas, quejas, etc.) para conocer la tasa de resolución en un plazo de 3 días hábiles.',unistr('检查客户服务电子邮件（查询、投诉等），了解 3 个工作日内的解决率。\u000a1. 解决率为[85, 100]，给出30分。\u000a2. 解决率为[70, 85)，给出15分。\u000a3. 解决率为[0, 70)，给0分。\u000a注：若考核期内无客户投诉邮件，则按总分的70%确定分数。'),unistr('Consulta los correos electrónicos de atención al cliente (consultas, quejas, etc.) para conocer el porcentaje de resolución en un plazo de 3 días laborables.\u000a1. La tasa de resolución es [85, 100], otorga 30 puntajes.\u000a2. La tasa de resolución es [70, 85), dé 15 puntuaciones.\u000a3. La tasa de resolución es [0, 70), otorga 0 puntuación.\u000aNota: Si no hay correos electrónicos de quejas de clientes dentro del período de evaluación, la puntuación se determinará en base al 70% de la puntuación total.'),'客户服务','Servicio al cliente',NULL);
INSERT INTO tqc__rules VALUES(105,'A-5-3','Customer Service','1 DAY CALL Execution','Online','Check whether work orders provided by the distributors have met 1DC requirements',30,23,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If it is met, give 30 scores;\u000aIf not, give 0 score.'),'1 DAY CALL 执行','LLAMADA DE 1 DÍA Ejecución','检查经销商提供的工单是否满足1DC要求','Verifique si las órdenes de trabajo proporcionadas por los distribuidores cumplen con los requisitos de 1DC',unistr('如果符合，打30分；\u000a如果没有，给0分。'),unistr('Si se cumple, dé 30 puntos;\u000aEn caso contrario, dé 0 puntos.'),'客户服务','Servicio al cliente',NULL);
INSERT INTO tqc__rules VALUES(106,'A-6-1','Service Procedure','Core Service Procedure Drill','Online',unistr('The service advisors at the store conduct drills according to the core service process checklist and provide feedback on the drill videos for scoring.\u000aNotes: 1. Scores exceeding 85 are considered qualified; 2. Service consultants who have been employed for more than three months are required to complete a drill, and the Q2 assessment scope includes service advisors whose LMS registration dates are before April 2026.\u000aPass rate=number of personnel whose scores exceeding 85/ all the personnels attending the drill'),30,24,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('Threshold Requirement: The distributor need to provide a video of the service process drills for personnel required in each store during the assessment period.\u000a\u000aIt should score as follows:\u000a1. The pass rate of the drill is 100%, give 30 scores;\u000a2. The pass rate of the drill is [75%, 100%）, give 30 scores;\u000a3. The pass rate of the drill is [50%, 75%), give 30 scores;\u000a4. The pass rate of the drill is [0, 50%) give 30 scores;'),'核心服务流程演练','Simulacro de procedimiento de servicio básico',unistr('门店服务顾问根据核心服务流程清单进行演练，并反馈演练视频进行评分。\u000a注：1、成绩超过85分视为合格； 2.入职三个月以上的服务顾问需完成演练，Q2考核范围包括LMS注册日期在2026年4月之前的服务顾问。\u000a通过率=分数超过85分的人员数/参加演练的人员总数'),unistr('Los asesores de servicio de la tienda realizan simulacros de acuerdo con la lista de verificación del proceso de servicio principal y brindan comentarios sobre los videos de simulacros para calificar.\u000aNotas: 1. Las puntuaciones superiores a 85 se consideran calificadas; 2. Los consultores de servicios que hayan trabajado durante más de tres meses deben completar un simulacro, y el alcance de la evaluación del segundo trimestre incluye a los asesores de servicios cuyas fechas de registro en el LMS sean anteriores a abril de 2026.\u000aTasa de aprobación = número de personal cuyas puntuaciones superan 85/todo el personal que asiste al simulacro'),unistr('门槛要求：经销商需提供考核期间各门店所需人员服务流程演练视频。\u000a\u000a其得分应如下：\u000a1、演练合格率为100%，给30分；\u000a2. 演练通过率为[75%, 100%），给30分；\u000a3、演练通过率为[50%,75%)，给30分；\u000a4. 演练通过率为[0, 50%) 打30分；'),unistr('Requisito de umbral: el distribuidor debe proporcionar un video de los simulacros del proceso de servicio para el personal requerido en cada tienda durante el período de evaluación.\u000a\u000aDebe puntuar de la siguiente manera:\u000a1. La tasa de aprobación del ejercicio es del 100%, dé 30 puntajes;\u000a2. La tasa de aprobación del ejercicio es [75%, 100%）, dé 30 puntajes;\u000a3. La tasa de aprobación del ejercicio es [50%, 75%), dé 30 puntajes;\u000a4. La tasa de aprobación del ejercicio es [0, 50%) y otorga 30 puntajes;'),'服务流程','Procedimiento de servicio',NULL);
INSERT INTO tqc__rules VALUES(107,'A-7-1','Monthly Report','Monthly Report','Online','Check whether distributor has submitted Monthly Report to BYD before each 10th of next month.',60,25,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('Mainly inspect on timeliness of submission, the completeness and accury of the content.\u000aNeed to submit 3 pieces (each piece for each month) in total.\u000aIf 3 pieces are submitted, give 60 scores;\u000aIf 2 pieces are submitted, give 40 scores;\u000aIf 1 piece is submitted, give 20 scores.\u000aIf 0 piece is submitted, give 0 score.'),'月度报告','Informe Mensual','每月10日前检查经销商是否向比亚迪提交月报。','Verifique si el distribuidor ha enviado el informe mensual a BYD antes de cada día 10 del próximo mes.',unistr('主要检查提交的及时性、内容的完整性和准确性。\u000a共需提交3份（每月每份）。\u000a如果提交3件，给60分；\u000a如果提交2件，给40分；\u000a如果提交1件，则给20分。\u000a如果提交 0 件，则给 0 分。'),unistr('Principalmente inspeccionar la puntualidad en la presentación, la integridad y exactitud del contenido.\u000aEs necesario enviar 3 piezas (cada pieza por cada mes) en total.\u000aSi se presentan 3 piezas, dé 60 puntos;\u000aSi se presentan 2 piezas, dé 40 puntos;\u000aSi se envía 1 pieza, dé 20 puntos.\u000aSi se envía 0 pieza, dé 0 puntuación.'),'月度报告','Informe Mensual',NULL);
INSERT INTO tqc__rules VALUES(108,'B-1-1','Central Warehouse Management','Inventory Management','On-site',unistr('Randomly inspect 20 types of spare parts (including A&B spare parts) and check whether the physical quantity matches the actual inventory quantity in the inventory management system.\u000aNote: Agents need to assist in completing the inspection within half an hour according to the selected list. Otherwise, this item will be given 0 score.'),10,26,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If the total gap quantity of 20 types is ≤ 4, give 10 scores; If gap quantity ＞4, give 0 score.','库存管理','Gestión de inventario',unistr('随机抽查20种备件（含A、B类备件），核对实物数量与库存管理系统实际库存数量是否相符。\u000a注：代理商需根据所选清单在半小时内协助完成验货。否则，该项目将被给予0分。'),unistr('Inspeccione aleatoriamente 20 tipos de repuestos (incluidos repuestos A y B) y verifique si la cantidad física coincide con la cantidad real del inventario en el sistema de gestión de inventario.\u000aNota: Los agentes deben ayudar a completar la inspección dentro de media hora según la lista seleccionada. En caso contrario, este ítem recibirá 0 puntuación.'),'如果20种类型的缺口总数≤4，则给10分；如果差距数量>4，则给0分。','Si la cantidad total de brechas de 20 tipos es ≤ 4, otorgue 10 puntajes; Si la cantidad de espacio es >4, dé 0 puntuación.','中央仓库管理','Gestión de almacenes centrales',NULL);
INSERT INTO tqc__rules VALUES(109,'B-1-2','Central Warehouse Management','Power Battery Pack Storage','On-site','Check whether the distributor is equipped with power battery pack in inventory according to the vehicle model: each vehicle model needs to be equipped with quantity≥ 1.',10,27,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If the rate of vehicle models equipped with power battery pack in inventory ≥ 80%, give 10 scores;\u000aIf the rate of vehicle models＜80%, give 0 score.'),'动力电池组存储','Almacenamiento del paquete de baterías','根据车型检查经销商库存是否配备动力电池组：每种车型需配备数量≥1个。','Verifique si el distribuidor está equipado con un paquete de baterías de energía en el inventario según el modelo de vehículo: cada modelo de vehículo debe estar equipado con una cantidad ≥ 1.',unistr('库存动力电池组搭载率≥80%的车型，给予10分；\u000a如果车型比例＜80%，则给0分。'),unistr('Si la tasa de modelos de vehículos equipados con paquete de batería eléctrica en el inventario es ≥ 80%, otorgue 10 puntajes;\u000aSi la tasa de modelos de vehículos <80%, dé 0 puntuación.'),'中央仓库管理','Gestión de almacenes centrales',NULL);
INSERT INTO tqc__rules VALUES(110,'B-1-5','Central Warehouse Management','Safety Belts and Airbags','On-site','Check if the inventory of safety belts and airbags is equipped according to the vehicle model: each vehicle model needs to be equipped with ≥ 1 safety belt and ≥ 1 airbag.',10,28,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. If all models are equipped with seat belts, give 5 scores; otherwise, give 0 score;\u000a2. If all models are equipped with airbags, give 5 scores; otherwise, give 0 score.'),'安全带和安全气囊','Cinturones de seguridad y bolsas de aire','按车型检查安全带和安全气囊库存是否配备：每种车型需配备≥1条安全带和≥1个安全气囊。','Verifique si el inventario de cinturones de seguridad y bolsas de aire está equipado según el modelo de vehículo: cada modelo de vehículo debe estar equipado con ≥ 1 cinturón de seguridad y ≥ 1 bolsa de aire.',unistr('1、如果所有车型均配备安全带，则打5分；否则，给0分；\u000a2、如果所有车型均配备安全气囊，则打5分；否则，给0分。'),unistr('1. Si todos los modelos están equipados con cinturones de seguridad, dé 5 puntos; de lo contrario, dé 0 puntuación;\u000a2. Si todos los modelos están equipados con bolsas de aire, dé 5 puntos; de lo contrario, dé 0 puntuación.'),'中央仓库管理','Gestión de almacenes centrales',NULL);
INSERT INTO tqc__rules VALUES(111,'C-1-1','Exclusive Hardware','Facade','On-site',unistr('1. Check whether there is a BYD logo on the facade of the service store, and check whether the facade is clean and aesthetically visible;\u000a2. Check whether the logo font and color of BYD Service complies with BYD''s VI design requirements.'),10,29,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all requirements, give 10 scores;\u000aIf don''t comply with any of the requirements, give 0 score.'),'正面','Fachada',unistr('1、检查服务店门面是否有比亚迪标志，并检查门面是否干净、美观；\u000a2、检查比亚迪服务标志字体、颜色是否符合比亚迪VI设计要求。'),unistr('1. Verifique si hay un logotipo de BYD en la fachada de la tienda de servicios y verifique si la fachada está limpia y estéticamente visible;\u000a2. Verifique si la fuente y el color del logotipo del Servicio BYD cumplen con los requisitos de diseño VI de BYD.'),unistr('如果符合所有要求，则打10分；\u000a如果不符合任何要求，则给 0 分。'),unistr('Si cumple con todos los requisitos, dé 10 puntos;\u000aSi no cumple con alguno de los requisitos, dé 0 puntuación.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(112,'C-1-2','Exclusive Hardware','Reception Area','On-site',unistr('1. Check whether there is a BYD logo in the customer reception area, and inspect the reception area background wall or reception table signage;\u000a2. Check whether the logo of BYD Service complies with BYD''s VI design requirements;\u000a3. If the customer reception area is in the show room, the BYD Service logo should also be displayed.\u000a4. Check if the brightness is greater than 300 Lux;\u000a5. Size Requirement\u000aService Center≥32㎡, A Class≥24㎡, B Class≥16㎡, C Class≥8㎡, D Class is required but no area requirement.\u000aThe reception area can be combined with the customer lounge area, with a total area equal to the sum of the two.'),12,30,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all requirements, give 12 scores;\u000aIf don''t comply with any of the requirements, give 0 score.'),'接待区','Área de recepción',unistr('1、检查客户接待区是否有比亚迪标志，并检查接待区背景墙或接待台标识牌；\u000a2、检查比亚迪服务标志是否符合比亚迪VI设计要求；\u000a3、如果客户接待区位于展厅内，还应展示比亚迪服务标志。\u000a4、检查亮度是否大于300Lux；\u000a5、尺寸要求\u000a服务中心≥32平方米，A级≥24平方米，B级≥16平方米，C级≥8平方米，D级有要求，但无面积要求。\u000a接待区可与顾客休息区合并，总面积等于两者之和。'),unistr('1. Verifique si hay un logotipo de BYD en el área de recepción de clientes e inspeccione la pared del fondo del área de recepción o la señalización de la mesa de recepción;\u000a2. Verificar si el logotipo del Servicio BYD cumple con los requisitos de diseño VI de BYD;\u000a3. Si el área de recepción de clientes está en la sala de exposición, también se deberá mostrar el logotipo de BYD Service.\u000a4. Verifique si el brillo es superior a 300 Lux;\u000a5. Requisito de tamaño\u000aCentro de servicio≥32㎡, Clase A≥24㎡, Clase B≥16㎡, Clase C≥8㎡, Clase D se requiere pero no hay requisito de área.\u000aLa zona de recepción se puede combinar con la zona de salón de clientes, quedando una superficie total igual a la suma de ambas.'),unistr('如果符合所有要求，则打12分；\u000a如果不符合任何要求，则给 0 分。'),unistr('Si cumple con todos los requisitos, dé 12 puntos;\u000aSi no cumple con alguno de los requisitos, dé 0 puntuación.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(113,'C-1-3','Exclusive Hardware','Customer Lounge','On-site',unistr('1. Check if there is a coffee bar in the customer lounge area;\u000a2. Check if the brightness is greater than 300 Lux;\u000a3. Size Requirement:\u000aService Center≥45㎡, A Class≥31㎡, B Class≥21㎡, C Class≥12㎡, D Class is required but no area requirement.\u000aThe reception area can be combined with the customer lounge area, with a total area equal to the sum of the two.'),12,31,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all requirements, give 12 scores;\u000aIf don''t comply with any of the requirements, give 0 score.'),'客户休息室','Sala de clientes',unistr('1、检查顾客休息区是否有咖啡吧；\u000a2、检查亮度是否大于300Lux；\u000a3.尺寸要求：\u000a服务中心≥45平方米，A级≥31平方米，B级≥21平方米，C级≥12平方米，D级有要求，但无面积要求。\u000a接待区可与顾客休息区合并，总面积等于两者之和。'),unistr('1. Compruebe si hay una cafetería en la zona de salón para clientes;\u000a2. Compruebe si el brillo es superior a 300 Lux;\u000a3. Requisito de tamaño:\u000aCentro de servicio≥45㎡, Clase A≥31㎡, Clase B≥21㎡, Clase C≥12㎡, Clase D se requiere pero no hay requisito de área.\u000aLa zona de recepción se puede combinar con la zona de salón de clientes, quedando una superficie total igual a la suma de ambas.'),unistr('如果符合所有要求，则打12分；\u000a如果不符合任何要求，则给 0 分。'),unistr('Si cumple con todos los requisitos, dé 12 puntos;\u000aSi no cumple con alguno de los requisitos, dé 0 puntuación.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(114,'C-1-4','Exclusive Hardware','Customer Toilet','On-site',unistr('Size Requirement:\u000aService Center≥20㎡, A Class≥15㎡, B Class≥10㎡, C Class≥10㎡, D Class is required but no area requirement.'),2,32,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'顾客厕所','Baño del cliente',unistr('尺寸要求：\u000a服务中心≥20平方米，A级≥15平方米，B级≥10平方米，C级≥10平方米，D级有要求，但无面积要求。'),unistr('Requisito de tamaño:\u000aCentro de servicio≥20㎡, Clase A≥15㎡, Clase B≥10㎡, Clase C≥10㎡, Clase D se requiere pero no hay requisito de área.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(115,'C-1-5','Exclusive Hardware','Workshop VI','On-site',unistr('Workshop VI complies with BYD''s store construction standards, with gray (Pantone Coolgray 3C) and white color schemes. The workshop floor is coated with epoxy floor paint or tiles, with a height of 4m and a dado height of 1.8m; There is a maintenance bay signage hanged on the lift with dimensions of 0.3m*0.6m.\u000aNote: BYD maintenance bay dimensions can be flexibly adjusted according to the actual site conditions, with a width of 4±0.5m and a length of 7±1m.'),2,33,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'工作坊六','Taller VI',unistr('六号车间符合比亚迪专卖店建设标准，配色为灰色（Pantone Coolgray 3C）和白色。车间地面涂环氧地坪漆或瓷砖，高度4m，墙裙高度1.8m；电梯上悬挂有维修间标牌，尺寸为0.3m*0.6m。\u000a注：比亚迪维修间尺寸可根据现场实际情况灵活调整，宽度为4±0.5m，长度为7±1m。'),unistr('Workshop VI cumple con los estándares de construcción de tiendas de BYD, con combinaciones de colores gris (Pantone Coolgray 3C) y blanco. El piso del taller está recubierto con pintura epoxi para pisos o losas, con una altura de 4 m y una altura de ranura de 1,8 m; Hay una señalización del puesto de mantenimiento colgada en el ascensor con unas dimensiones de 0,3 m x 0,6 m.\u000aNota: Las dimensiones del módulo de mantenimiento BYD se pueden ajustar de manera flexible según las condiciones reales del sitio, con un ancho de 4 ± 0,5 my una longitud de 7 ± 1 m.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(116,'C-1-6','Exclusive Hardware','Workshop Service Boards','On-site',unistr('Check if there are service boards in the workshop and if the signs comply with VI standards.\u000aIf there is any content in boards, and the VI meets BYD requirements, give full scores.'),2,34,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'车间服务板','Tableros de servicio de taller',unistr('检查车间内是否有服务牌，标志是否符合VI标准。\u000a如果板上有内容，且VI满足比亚迪要求，则打满分。'),unistr('Verificar si existen tableros de servicio en el taller y si los letreros cumplen con las normas VI.\u000aSi hay algún contenido en los foros y el VI cumple con los requisitos de BYD, proporcione la puntuación completa.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(117,'C-1-7','Exclusive Hardware','Maintenance Bay QTY','On-site',unistr('Calculate separately according to the lift bay, tire bay, and four-wheel alignment bay:\u000aLift bay:\u000aService Center≥12, A Class≥8, B Class≥5, C Class≥3, D Class≥2.\u000aThe lifting capacity of should ≥3.5t, and the lift VI should meet BYD''s store construction standards: it is gray (Pantone Coolgray 3C) and features a white BYD logo printed on it;\u000aFour-wheel alignment bay:\u000aService stores of all classes should have 1 four-wheel alignment bay.\u000aTire bay:\u000aService stores of service center, and A/B/C/D Class should have 1 tire bay；\u000aD Class is not mandatorily required to set. If not set, also give full score.'),6,35,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 6 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'维修站数量','Cantidad de bahía de mantenimiento',unistr('按照举升台、轮胎台、四轮定位台分别计算：\u000a电梯间：\u000a服务中心≥12个，A类≥8个，B类≥5个，C类≥3个，D类≥2个。\u000a起重能力≥3.5t，电梯VI满足比亚迪专卖店建设标准：灰色（Pantone Coolgray 3C），上面印有白色BYD标志；\u000a四轮定位台：\u000a各类维修店应配备1个四轮定位台。\u000a轮胎舱：\u000a服务中心服务店，A/B/C/D级应有1个轮胎舱；\u000aD级不强制要求设置。如果没有设置，也给满分。'),unistr('Calcule por separado según el compartimento de elevación, el compartimento de neumáticos y el compartimento de alineación de las cuatro ruedas:\u000aBahía de ascensor:\u000aCentro de servicio≥12, Clase A≥8, Clase B≥5, Clase C≥3, Clase D≥2.\u000aLa capacidad de elevación debe ser ≥3,5 t, y el elevador VI debe cumplir con los estándares de construcción de tiendas de BYD: es gris (Pantone Coolgray 3C) y presenta un logotipo BYD blanco impreso en él;\u000aBahía de alineación de cuatro ruedas:\u000aLos talleres de servicio de todas las clases deben tener 1 puesto de alineación de las cuatro ruedas.\u000aBahía de neumáticos:\u000aLas tiendas de servicio del centro de servicio y las clases A/B/C/D deben tener 1 compartimento para neumáticos;\u000aLa clase D no es obligatoria para configurar. Si no está establecido, también dé la puntuación completa.'),unistr('如果符合所有检查要求，则打6分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 6 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(118,'C-1-8','Exclusive Hardware','Charger QTY','On-site',unistr('Workshop(≥7kw AC): Service Center≥2, A Class≥2, B Class≥2, C Class≥2, D Class≥1;\u000aParking Area(≥7kw AC): Service Center≥8, A Class≥5, B Class≥3, C Class≥2, D Class≥1.\u000a*If the chargers can only be installed inside of the service stores because of construction limimations, the total charger qty make sense.'),2,36,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'充电器数量','Cantidad del cargador',unistr('车间（≥7kw AC）：服务中心≥2个，A类≥2个，B类≥2个，C类≥2个，D类≥1个；\u000a停车位（≥7kw AC）：服务中心≥8个，A类≥5个，B类≥3个，C类≥2个，D类≥1个。\u000a*如果由于施工限制充电器只能安装在服务店内，则充电器总数量是有意义的。'),unistr('Taller (≥7kw AC): Centro de servicio≥2, Clase A≥2, Clase B≥2, Clase C≥2, Clase D≥1;\u000aÁrea de estacionamiento (≥7kw AC): Centro de servicio≥8, Clase A≥5, Clase B≥3, Clase C≥2, Clase D≥1.\u000a*Si los cargadores solo se pueden instalar dentro de las tiendas de servicio debido a limitaciones de construcción, la cantidad total de cargadores tiene sentido.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(119,'C-1-9','Exclusive Hardware','Workshop Illumination','On-site',unistr('Maintenance bay lighting:\u000apolishing bay ≥ 1000 Lux, girder calibration and panel repair ≥ 700 Lux, maintenance bay and vehicle moving channel ≥ 500 Lux, workshop lighting ≥ 300 Lux.'),2,37,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'车间照明','Iluminación del taller',unistr('维修间照明：\u000a抛光间≥1000Lux，大梁校正及面板维修≥700Lux，维修间及车辆移动通道≥500Lux，车间照明≥300Lux。'),unistr('Iluminación de la bahía de mantenimiento:\u000aBahía de pulido ≥ 1000 Lux, calibración de vigas y reparación de paneles ≥ 700 Lux, Bahía de mantenimiento y canal de movimiento de vehículos ≥ 500 Lux, iluminación del taller ≥ 300 Lux.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(120,'C-1-14','Exclusive Hardware','Power-train Repair Room','On-site','Service Center≥30㎡, A Class≥21㎡, B Class≥18㎡, C Class≥5㎡, D Class is required but no area requirement.',2,38,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'动力总成修理室','Sala de reparación de trenes de potencia','服务中心≥30平方米，A级≥21平方米，B级≥18平方米，C级≥5平方米，D级有要求，但无面积要求。','Centro de servicio≥30㎡, Clase A≥21㎡, Clase B≥18㎡, Clase C≥5㎡, Clase D se requiere pero no hay requisito de área.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(121,'C-1-15','Exclusive Hardware','Power Battery Turnover Room','On-site','Service Center≥30㎡, A Class≥15㎡, B Class≥15㎡, C Class≥8㎡, D Class is required but no area requirement.',2,39,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'动力电池周转室','Sala de rotación de baterías de energía','服务中心≥30平方米，A级≥15平方米，B级≥15平方米，C级≥8平方米，D级有要求，但无面积要求。','Centro de servicio≥30㎡, Clase A≥15㎡, Clase B≥15㎡, Clase C≥8㎡, Clase D se requiere pero no hay requisito de área.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(122,'C-1-16','Exclusive Hardware','Mobile Fire Water Pool','On-site','Each service store should be equipped with one mobile fire water pool, and has no size requirement on fire pool area.',2,40,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'移动消防水池','Piscina de agua contra incendios móvil','每个服务店应配备1个移动消防水池，消防水池面积无大小要求。','Cada almacén de servicios debe estar equipado con una piscina de agua contra incendios móvil y no tiene ningún requisito de tamaño en el área de la piscina contra incendios.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(123,'C-1-17','Exclusive Hardware','Tool Room','On-site','Service Center≥15㎡, A Class≥15㎡, B Class≥10㎡, C Class≥10㎡, D Class is required but no area requirement.',2,41,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'工具室','Sala de herramientas','服务中心≥15平方米，A级≥15平方米，B级≥10平方米，C级≥10平方米，D级有要求，但无面积要求。','Centro de servicio≥15㎡, Clase A≥15㎡, Clase B≥10㎡, Clase C≥10㎡, Clase D se requiere pero no hay requisito de área.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(124,'C-1-18','Exclusive Hardware','Workshop Flow','On-site',unistr('The workshop circulation line adheres to BYD''s store construction standards, featuring a reasonable, clear, and complete one-way circular or two-way circulation route. The vehicle reception channel and the flow and turnover of vehicles in the workshop should be smooth and unobstructed;\u000aThe equipment and facilities are marked with fixed lines, which are reasonably planned, easy to use, and clear and complete;\u000aThe width of workshop flow:\u000aOne way channel≥5m, double way channel≥6m.'),2,42,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'车间流程','Flujo del taller',unistr('车间动线遵循比亚迪专卖店建设标准，具有合理、清晰、完整的单向循环或双向动线路线。车辆接待通道及车间内车辆的流通、周转应畅通无阻；\u000a设备设施有固定线路标识，规划合理，使用方便，清晰齐全；\u000a车间流程宽度：\u000a单向通道≥5m，双向通道≥6m。'),unistr('La línea de circulación del taller cumple con los estándares de construcción de tiendas de BYD y presenta una ruta de circulación circular unidireccional o bidireccional razonable, clara y completa. El canal de recepción de vehículos y el flujo y rotación de vehículos en el taller deberán ser fluidos y sin obstáculos;\u000aLos equipos e instalaciones están marcados con líneas fijas, razonablemente planificadas, fáciles de usar, claras y completas;\u000aEl ancho del flujo del taller:\u000aCanal unidireccional≥5m, canal bidireccional≥6m.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(125,'C-1-19','Exclusive Hardware','Workshop Office','On-site',unistr('Service Center≥12㎡, A Class≥8㎡, B Class≥6㎡, C Class is required but no area requirement, D Class is not mandatorily required to set; If not set, also give full score.\u000aWorkshop office can be combined with the staff lounge.'),2,43,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'车间办公室','Oficina del taller',unistr('服务中心≥12㎡，A级≥8㎡，B级≥6㎡，C级为必设但面积无要求，D级不强制要求设置；如果没有设置，也给满分。\u000a车间办公室可与员工休息室合并。'),unistr('Centro de servicio≥12㎡, Clase A≥8㎡, Clase B≥6㎡, Se requiere Clase C pero no hay requisito de área, No se requiere establecer obligatoriamente la Clase D; Si no está establecido, también dé la puntuación completa.\u000aLa oficina del taller se puede combinar con la sala del personal.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(126,'C-1-20','Exclusive Hardware','Workshop Toilet','On-site','Service stores of all classes are required but no area requirement.',2,44,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'车间厕所','Baño de taller','需要所有级别的服务店，但没有面积要求。','Se requieren tiendas de servicios de todas las clases, pero no hay requisitos de área.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(127,'C-1-21','Exclusive Hardware','Meeting & Training Room','On-site',unistr('Service Center≥24㎡, A Class≥18㎡, B Class≥15㎡, C Class≥12㎡.\u000aD Class is not mandatorily required to set. If it is set, give full score; if not set, give no score.'),2,45,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'会议室及培训室','Sala de reuniones y formación',unistr('服务中心≥24平方米，A类≥18平方米，B类≥15平方米，C类≥12平方米。\u000aD级不强制要求设置。如果设定，则给满分；如果未设置，则不评分。'),unistr('Centro de servicio≥24㎡, Clase A≥18㎡, Clase B≥15㎡, Clase C≥12㎡.\u000aLa clase D no es obligatoria para configurar. Si está establecido, dé la puntuación total; si no está establecido, no dé puntuación.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(128,'C-1-22','Exclusive Hardware','Staff Lounge','On-site',unistr('Service stores of all classes are not mandatorily required to set.\u000aStaff lounge can be combined with the Workshop office.'),2,46,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'员工休息室','Salón del personal',unistr('所有类别的服务店不强制要求设置。\u000a员工休息室可以与车间办公室合并。'),unistr('Los establecimientos de servicio de todas las clases no están obligados a instalarse.\u000aLa sala de personal se puede combinar con la oficina del taller.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(129,'C-1-23','Exclusive Hardware','Waste Oil Area','On-site','Service stores of all classes are required but no area requirement.',2,47,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'废油区','Área de aceites usados','需要所有级别的服务店，但没有面积要求。','Se requieren tiendas de servicios de todas las clases, pero no hay requisitos de área.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(130,'C-1-25','Exclusive Hardware','Car Washing Area','On-site',unistr('Bay qty:\u000aService Center≥2, A Class≥1, B Class≥1, C Class≥1.\u000aD Class is not mandatorily required to set; If not set, also give full score.'),2,48,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'洗车区','Área de lavado de autos',unistr('海湾数量：\u000a服务中心≥2个，A类≥1个，B类≥1个，C类≥1个。\u000aD级不强制要求设置；如果没有设置，也给满分。'),unistr('Cantidad de bahía:\u000aCentro de servicio≥2, Clase A≥1, Clase B≥1, Clase C≥1.\u000aLa Clase D no es obligatoria para configurar; Si no está establecido, también dé la puntuación completa.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(131,'C-1-26','Exclusive Hardware','Claim Parts Storage Room','On-site','Service stores of all classes should set, but have no size requirement.',2,49,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'领取零件储藏室','Sala de almacenamiento de piezas de reclamo','各类服务店均应设置，但无规模要求。','Las tiendas de servicios de todas las clases deben establecerse, pero no tienen requisitos de tamaño.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(132,'C-1-28','Exclusive Hardware','Automobile Wheel Aligner','On-site',unistr('Should be equipped with 1 for service stores of Service center and A/B/C Class.\u000aD Class is not mandatorily required to set; If not set, also give full score.'),2,50,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'汽车四轮定位仪','Alineador de ruedas de automóvil',unistr('服务中心及A/B/C级服务店应配备1个。\u000aD级不强制要求设置；如果没有设置，也给满分。'),unistr('Debe estar equipado con 1 para tiendas de servicio de centro de servicio y clase A/B/C.\u000aLa Clase D no es obligatoria para configurar; Si no está establecido, también dé la puntuación completa.'),unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(133,'C-1-29','Exclusive Hardware','Tire Changer','On-site','Should be equipped with ≥1 for service stores of all classes, with its specifications meet the disassembly and assembly requirements for tires of 22 inches and above.',2,51,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'轮胎拆装机','Cambiador de neumáticos','各类维修店应配备≥1个，其规格满足22英寸及以上轮胎拆装要求。','Deberá estar equipado con ≥1 para talleres de servicio de todas las clases, cuyas especificaciones cumplan con los requisitos de desmontaje y montaje para neumáticos de 22 pulgadas en adelante.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(134,'C-1-30','Exclusive Hardware','Tire Dynamic Balance Machine','On-site','Should be equipped with ≥1 for service stores of all classes.',2,52,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 2 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'轮胎动平衡机','Máquina de equilibrio dinámico de neumáticos','各类服务店应配备≥1个。','Debe estar equipado con ≥1 para tiendas de servicios de todas las clases.',unistr('如果符合所有检查要求，则打2分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 2 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(135,'C-1-32','Exclusive Hardware','Workshop Warehouse','On-site',unistr('1. For stores with central warehouse, workshop warehouse has no size requirements;\u000a2. Stores without a central warehouse should meet the following requirements:\u000aService Center≥336㎡, A Class≥144㎡, B Class≥120㎡, C Class≥72㎡, D Class≥48㎡.'),5,53,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 5 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'车间仓库','Almacén Taller',unistr('1、对于有中央仓库的门店，车间仓库没有尺寸要求；\u000a2、无中心仓库的店铺应符合以下要求：\u000a服务中心≥336平方米，A类≥144平方米，B类≥120平方米，C类≥72平方米，D类≥48平方米。'),unistr('1. Para las tiendas con almacén central, el almacén taller no tiene requisitos de tamaño;\u000a2. Los almacenes sin almacén central deberán cumplir los siguientes requisitos:\u000aCentro de servicio≥336㎡, Clase A≥144㎡, Clase B≥120㎡, Clase C≥72㎡, Clase D≥48㎡.'),unistr('如果符合所有检查要求，则打5分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 5 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(136,'C-1-34','Exclusive Hardware','Special Tool','On-site','Each service store should be equipped with at least one VDS.',5,54,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with the check requirements, give 5 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'专用工具','Herramienta especial','每个服务店应至少配备一台VDS。','Cada tienda de servicios debe estar equipada con al menos un VDS.',unistr('符合检查要求的，打5分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con los requisitos de verificación, otorgue 5 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(137,'C-1-35','Exclusive Hardware','Special Tool','On-site',unistr('The store should be equipped with special tools referring to BYD''s equipment standards (find in BYD Special Tools List-2025);\u000aAnd it is required to be neatly arranged with tool identification tag and should be easily accessible.'),10,55,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. If the store is equipped with all the necessary special tools, give 10 scores; If the necessary special tools is not completely equipped, give 0 score.\u000a2. Tool management complies with requirement, give 5 scores; Not comply with any of the requirement, give 0 score.'),'专用工具','Herramienta especial',unistr('店内应配备参照比亚迪设备标准的专用工具（参见《比亚迪专用工具清单-2025》）；\u000a并要求整齐排列有工具识别标签，并应易于取用。'),unistr('La tienda debe estar equipada con herramientas especiales que cumplan con los estándares de equipos de BYD (encuéntrelas en la Lista de herramientas especiales de BYD-2025);\u000aY es necesario que esté ordenado con una etiqueta de identificación de herramienta y que sea de fácil acceso.'),unistr('1、如果商店配备了所有必要的专用工具，则给10分；如果必要的专用工具没有配备齐全，则给0分。\u000a2.刀具管理符合要求，打5分；不符合任何一项要求，给0分。'),unistr('1. Si la tienda está equipada con todas las herramientas especiales necesarias, dé 10 puntos; Si las herramientas especiales necesarias no están completamente equipadas, otorgue una puntuación de 0.\u000a2. La gestión de herramientas cumple con los requisitos, otorgue 5 puntajes; No cumplir con ninguno de los requisitos, otorgar 0 puntaje.'),'独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(138,'C-1-36','Exclusive Hardware','Service Materials','On-site',unistr('1. Check whether a service store has maintenance three-piece set（14014852-00）, environmental three-piece set（14014850-00）, floor mat（14035193-00）, delivery envelope.（14709236-00）\u000a2. Check whether the store uses service materials in after-sales service process on-site.'),20,56,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If all types of material are found and used in on-site inspection, give 20 scores; If one or more items are missing or not used during on-site inspection, give 0 score.','服务材料','Materiales de servicio',unistr('1、检查服务店是否有保养三件套（14014852-00）、环保三件套（14014850-00）、地垫（14035193-00）、送货信封（14709236-00）\u000a2、现场检查店铺在售后服务过程中是否使用服务材料。'),unistr('1. Verifique si una tienda de servicios tiene un juego de tres piezas de mantenimiento (14014852-00), un juego ambiental de tres piezas (14014850-00), un tapete para el piso (14035193-00), un sobre de entrega (14709236-00).\u000a2. Verifique si la tienda utiliza materiales de servicio en el proceso de servicio posventa en el sitio.'),'现场检查发现并使用各类材料的，打20分；现场检查时缺少或未使用一项或多项的，给予0分。','Si se encuentran y utilizan todos los tipos de materiales en la inspección in situ, dé 20 puntos; Si uno o más elementos faltan o no se utilizan durante la inspección in situ, otorgue una puntuación de 0.','独家硬件','Hardware exclusivo',NULL);
INSERT INTO tqc__rules VALUES(139,'C-2-1','Exclusive Management','LMS Accounts for After-sales Service Store','On-site','Based on the attendance record docs and other information provided by the store, verify whether the service store has registered LMS accounts for all current employees and whether accounts have been cancelled for all resigned employees.',10,57,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If meet all requirement, give 10 scores; Otherwise, give 0 score.','售后服务店LMS账户','Cuentas LMS para tienda de servicio postventa','根据门店提供的考勤记录等信息，核实服务门店是否为所有在职员工注册了LMS账号，以及是否为所有离职员工注销了账号。','Según los documentos del registro de asistencia y otra información proporcionada por la tienda, verifique si la tienda de servicios ha registrado cuentas LMS para todos los empleados actuales y si las cuentas se han cancelado para todos los empleados renunciados.','如果满足全部要求，打10分；否则，给0分。','Si cumple con todos los requisitos, otorgue 10 puntajes; De lo contrario, dé 0 puntos.','独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(140,'C-2-2','Exclusive Management','Familiarity in IT System','On-site',unistr('TIS：\u000aLMS：\u000aDMS：\u000aTIS:\u000aRandomly check the operation familiarity on TIS system of one technician and one spare parts personnel.\u000a1. Technician: Randomly select a module from the EPC spare parts catalog, WSM maintenance manual, DSM diagnostic manual, WD circuit diagram, work hour query, and technical consultation, and the inspected person needs to operate it on site;\u000a2. Spare parts personnel: For the spare parts consultation module, the inspected person needs to operate on site.\u000aLMS:\u000aRandomly check the familiarity on LMS operation of two technicians, and have the inspected person operate it on site to check if they can identify the purpose of each module.\u000aDMS:\u000aFor distributor directly managed stores:\u000aRandomly check the familiarity on DMS operation of one service advisor, respectively in the material management, claim management, and maintenance management modules, have the inspected person to simulate creating the work order on site.\u000aFor stores managed by 3rd party:\u000aThe scores is the average scores of all distributor directly managed stores.'),15,58,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. TIS: If technician operates correctly, give 2.5 score; if operate wrongly, give 0 score;\u000a2. TIS: If spare parts personnel operates correctly, give 2.5 score; if operate wrongly, give 0 score;\u000a3. LMS: 1 technician can operate right, give 2.5 scores; 2 technicians can operate right, give 5 scores;\u000a4. DMS: Operate correctly, give 5 scores; if operate wrongly, give 0 score;'),'熟悉IT系统','Familiaridad en el sistema de TI.',unistr('TIS：\u000a学习管理系统：\u000a数据管理系统：\u000aTIS：\u000a抽查一名技术人员和一名备件人员对TIS系统的操作熟悉程度。\u000a1、技术人员：从EPC备件目录、WSM维修手册、DSM诊断手册、WD电路图、工时查询、技术咨询中随机选择一个模块，由受检人员现场操作；\u000a2、备件人员：对于备件咨询模块，需要被巡检人员现场操作。\u000a学习管理系统：\u000a随机检查两名技术人员对LMS操作的熟悉程度，并让被检查人员现场操作，检查是否能识别各模块的用途。\u000a数据管理系统：\u000a对于经销商直营店：\u000a随机检查一名服务顾问对DMS操作的熟悉程度，分别在物料管理、索赔管理、维修管理模块，让被检查人员现场模拟创建工单。\u000a对于第三方管理的商店：\u000a分数为所有经销商直营店的平均分。'),unistr('TIS:\u000aLMS:\u000aDMS:\u000aTIS:\u000aVerifique aleatoriamente la familiaridad con la operación del sistema TIS de un técnico y un personal de repuestos.\u000a1. Técnico: seleccione aleatoriamente un módulo del catálogo de repuestos de EPC, manual de mantenimiento de WSM, manual de diagnóstico de DSM, diagrama de circuito de WD, consulta de horas de trabajo y consulta técnica, y la persona inspeccionada debe operarlo en el sitio;\u000a2. Personal de repuestos: Para el módulo de consulta de repuestos, la persona inspeccionada debe operar en el sitio.\u000aLMS:\u000aVerifique aleatoriamente la familiaridad de dos técnicos con el funcionamiento del LMS y haga que la persona inspeccionada lo opere en el sitio para verificar si puede identificar el propósito de cada módulo.\u000aDMS:\u000aPara tiendas administradas directamente por el distribuidor:\u000aVerifique aleatoriamente la familiaridad con el funcionamiento del DMS de un asesor de servicio, respectivamente en los módulos de gestión de materiales, gestión de reclamos y gestión de mantenimiento, y haga que la persona inspeccionada simule la creación de la orden de trabajo en el sitio.\u000aPara tiendas administradas por terceros:\u000aLas puntuaciones son las puntuaciones medias de todas las tiendas gestionadas directamente por los distribuidores.'),unistr('1. TIS：技术人员操作正确，打2.5分；如果操作错误，给0分；\u000a2、TIS：备件人员操作正确，打2.5分；如果操作错误，给0分；\u000a3. LMS：1名技术人员能够正确操作，给予2.5分； 2名技术人员操作正确，给5分；\u000a4、DMS：操作正确，给5分；如果操作错误，给0分；'),unistr('1. TIS: Si el técnico opera correctamente, otorgue una puntuación de 2,5; si funciona incorrectamente, dé 0 puntuación;\u000a2. TIS: Si el personal de repuestos opera correctamente, otorgar puntuación de 2,5; si funciona incorrectamente, dé 0 puntuación;\u000a3. LMS: 1 técnico puede operar correctamente, otorga 2,5 puntajes; 2 técnicos pueden operar correctamente, otorgar 5 puntajes;\u000a4. DMS: opere correctamente, otorgue 5 puntajes; si funciona incorrectamente, dé 0 puntuación;'),'独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(141,'C-2-3','Exclusive Management','DMS work order Input','On-site','Verify that the DMS contains non-claim repair orders, and that the number of non-claim repair orders integrated into or recorded in the DMS accounts for at least 90% of the number of non-claim repair orders in the distributor''s own system.',15,59,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If the proportion of the number of work orders entered in DMS to the number of non - claim work orders in the proprietary system is ≥ 90%, give 15 scores; otherwise, give 0 score.','DMS工单输入','Entrada de orden de trabajo de DMS','验证 DMS 中是否包含无索赔维修订单，并且集成或记录在 DMS 中的无索赔维修订单数量至少占经销商自身系统中无索赔维修订单数量的 90%。','Verifique que el DMS contenga órdenes de reparación sin reclamo y que el número de órdenes de reparación sin reclamo integradas o registradas en el DMS represente al menos el 90% del número de órdenes de reparación sin reclamo en el propio sistema del distribuidor.','若DMS录入工单数量与专有系统中非索赔工单数量比例≥90%，则打15分；否则，给0分。','Si la proporción del número de órdenes de trabajo ingresadas en DMS con respecto al número de órdenes de trabajo sin reclamo en el sistema propietario es ≥ 90%, otorgue 15 puntajes; de lo contrario, dé 0 puntuación.','独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(142,'C-2-4','Exclusive Management','Service Appointment Waiting Time','On-site',unistr('On-site verification of service appointment waiting time may be conducted through WhatsApp, telephone records, or dealer systems\u000a(including review of WhatsApp chat records and detailed call / system records).\u000a\u000aService appointment waiting time =\u000aEarliest appointment date offered by the dealer − Customer''s requested appointment date.\u000a\u000aIf the customer’s requested appointment date is not clearly recorded,\u000athe customer’s requested date shall be deemed as the date when the appointment was made.'),10,60,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. If all 5 maintenance/repair orders have an appointment waiting time within 5 days, give 10 scores.\u000a2. If 5 maintenance/repair orders have an appointment waiting time within 5 days, give 5 scores.\u000a3. If fewer than 5 maintenance/repair orders have an appointment waiting time within 5 days, give 0 score.'),'服务预约等候时间','Tiempo de espera de cita de servicio',unistr('现场核实服务预约等待时间可通过WhatsApp、电话记录或经销商系统进行\u000a（包括查看WhatsApp聊天记录和详细通话/系统记录）。\u000a\u000a服务预约等待时间=\u000a经销商提供的最早预约日期 - 客户要求的预约日期。\u000a\u000a如果客户要求的预约日期没有明确记录，\u000a客户要求的日期将被视为预约日期。'),unistr('La verificación in situ del tiempo de espera de la cita de servicio se puede realizar a través de WhatsApp, registros telefónicos o sistemas del distribuidor.\u000a(incluida la revisión de los registros de chat de WhatsApp y los registros detallados de llamadas/sistema).\u000a\u000aTiempo de espera de cita de servicio =\u000aFecha de cita más temprana ofrecida por el distribuidor: fecha de cita solicitada por el cliente.\u000a\u000aSi la fecha de la cita solicitada por el cliente no está claramente registrada,\u000aLa fecha solicitada por el cliente se considerará como la fecha en la que se realizó la cita.'),unistr('1. 如果所有 5 个维护/维修订单都有 5 天内的预约等待时间，则打 10 分。\u000a2. 如果5天内有5个维护/维修订单有预约等待时间，则给5分。\u000a3. 如果5天内预约等待时间少于5个维护/维修订单，则给予0分。'),unistr('1. Si las 5 órdenes de mantenimiento/reparación tienen un tiempo de espera de cita dentro de los 5 días, otorgue 10 puntos.\u000a2. Si 5 órdenes de mantenimiento/reparación tienen un tiempo de espera de cita dentro de 5 días, dé 5 puntos.\u000a3. Si menos de 5 órdenes de mantenimiento/reparación tienen un tiempo de espera de cita dentro de los 5 días, otorgue 0 puntaje.'),'独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(143,'C-2-5','Exclusive Management','Inventory Management','On-site',unistr('Randomly inspect 10 types of spare parts to check if the physical quantity matches the actual inventory quantity in the inventory management system (Spare parts of type A&B must be checked).\u000aNote:\u000aThe service store needs to assist in completing the inspection within half an hour according to the selected list. Otherwise, this item will give 0 score.'),20,61,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If the total gap quantity of the 10 types is ≤ 2, give 20 scores;\u000aIf gap quantity ＞2, give 0 score.'),'库存管理','Gestión de inventario',unistr('随机抽查10种备件，检查实物数量与库存管理系统中的实际库存数量是否相符（A、B类备件必须检查）。\u000a注意：\u000a服务店需要根据选定的清单在半小时内协助完成检查。否则，该项目将给0分。'),unistr('Inspeccione aleatoriamente 10 tipos de repuestos para verificar si la cantidad física coincide con la cantidad real del inventario en el sistema de gestión de inventario (se deben verificar los repuestos de tipo A y B).\u000aNota:\u000aLa tienda de servicios debe ayudar a completar la inspección en media hora según la lista seleccionada. De lo contrario, este ítem dará 0 puntuación.'),unistr('如果10种类型的缺口总数≤2，则打20分；\u000a如果差距数量＞2，则给0分。'),unistr('Si la cantidad total de brechas de los 10 tipos es ≤ 2, dé 20 puntajes;\u000aSi la cantidad de espacio es >2, dé 0 puntuación.'),'独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(144,'C-2-6','Exclusive Management','Fulfill Rate of Regularly Prepared Spare Parts','On-site',unistr('According to BYD Spare Parts Recommendation List, check whether the recommended spare parts in the inventory management system meet the type requirements in the recommended spare parts list.\u000a\u000aFulfill rate=Number of recommended spare parts in stock in the store inventory management system/Number of spare parts in the recommended spare parts list * 100%.'),20,62,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Fulfill rate is [90%, 100%], give 20 scores.\u000a2. Fulfill rate is [75%, 90%), give 10 score.\u000a3. Fulfill rate is [60%, 75%), give 5 score.\u000a4. Fulfill rate is [0, 60%), give 0 score.'),'定期备件到位率','Tasa de cumplimiento de repuestos preparados periódicamente',unistr('根据比亚迪备件推荐清单，检查库存管理系统中的推荐备件是否符合推荐备件清单中的型号要求。\u000a\u000a履行率=门店库存管理系统库存推荐备件数量/推荐备件清单备件数量*100%。'),unistr('De acuerdo con la Lista de recomendaciones de repuestos de BYD, verifique si los repuestos recomendados en el sistema de gestión de inventario cumplen con los requisitos de tipo en la lista de repuestos recomendados.\u000a\u000aTasa de cumplimiento = Número de repuestos recomendados en stock en el sistema de gestión de inventario de la tienda/Número de repuestos en la lista de repuestos recomendados * 100%.'),unistr('1. 完成率为[90%, 100%]，给20分。\u000a2. 完成率为[75%, 90%)，给10分。\u000a3. 完成率为[60%, 75%)，给5分。\u000a4. 完成率为[0, 60%)，给0分。'),unistr('1. La tasa de cumplimiento es [90%, 100%], otorga 20 puntajes.\u000a2. La tasa de cumplimiento es [75%, 90%), otorga una puntuación de 10.\u000a3. La tasa de cumplimiento es [60%, 75%), otorga 5 puntos.\u000a4. La tasa de cumplimiento es [0, 60%), otorga 0 puntuación.'),'独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(145,'C-2-7','Exclusive Management','Q&A-Service Process','On-site','Select 5 questions from the 88 Questions for Service Advisor and randomly have 1 service advisor answer them on site.',5,63,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Answer correctly 5 questions, give 10 scores;\u000a2. Answer correctly 4 questions, give 5 scores;\u000a3. Answer correctly 3 questions or less, give 0 score.'),'问答-服务流程','Proceso de servicio de preguntas y respuestas','从88个问题服务顾问中选择5个问题，随机安排1名服务顾问现场解答。','Seleccione 5 preguntas de las 88 preguntas para el asesor de servicio y haga que 1 asesor de servicio las responda al azar en el sitio.',unistr('1.正确回答5题，给出10分；\u000a2.正确回答4题，给出5分；\u000a3.答对3题或以下，给0分。'),unistr('1. Responda correctamente 5 preguntas, dé 10 puntuaciones;\u000a2. Responda correctamente 4 preguntas, dé 5 puntuaciones;\u000a3. Responda correctamente 3 preguntas o menos, dé 0 puntuación.'),'独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(146,'C-2-8','Exclusive Management','Q&A-Technical Skills','On-site','Randomly select 5 technical related questions from the trainning exams bank and have 1 technician to answer them.',5,64,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Answer correctly 5 questions, give 10 scores;\u000a2. Answer correctly 4 questions, give 5 scores;\u000a3. Answer correctly 3 questions or less, give 0 score.'),'问答-技术技能','Preguntas y respuestas: habilidades técnicas','从培训考试库中随机抽取 5 道技术相关问题，并由 1 名技术人员进行解答。','Seleccione aleatoriamente 5 preguntas técnicas relacionadas del banco de exámenes de capacitación y haga que 1 técnico las responda.',unistr('1.正确回答5题，给出10分；\u000a2.正确回答4题，给出5分；\u000a3.答对3题或以下，给0分。'),unistr('1. Responda correctamente 5 preguntas, dé 10 puntuaciones;\u000a2. Responda correctamente 4 preguntas, dé 5 puntuaciones;\u000a3. Responda correctamente 3 preguntas o menos, dé 0 puntuación.'),'独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(147,'C-2-9','Exclusive Management','6S Management','On-site','Check whether the management of after-sales stores meets the requirements of 6S management standards.',20,65,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If meet the requirement, give 20 scores;\u000aOtherwise, give 0 score.'),'6S管理','Gestión 6S','检查售后店管理是否符合6S管理标准要求。','Compruebe si la gestión de las tiendas de posventa cumple con los requisitos de los estándares de gestión 6S.',unistr('符合要求的，打20分；\u000a否则，给0分。'),unistr('Si cumple con el requisito, otorgue 20 puntajes;\u000aDe lo contrario, dé 0 puntos.'),'独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(148,'C-2-10','Exclusive Management','Claim Parts Storage Management','On-site',unistr('According to the list of used parts provided by the Technical Claims Department, randomly select 5 sets of used parts for inspection:\u000a1. Check whether the relevant documents of the scrap records are saved completely and accurately. If there is no scrap report, the on-site scrap photos can be referred to.\u000a2. Check whether the used parts are well preserved.'),10,66,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Documents of the scrap records are saved completely and accurately, give 10 scores; Not saved completely and accurately, give 0 score.\u000a2. Used parts are well preserved, give 10 scores; Not preserved completely and accurately, give 0 score.'),'索赔零件存储管理','Gestión de almacenamiento de piezas de reclamación',unistr('根据技术索赔部提供的旧件清单，随机抽取5套旧件进行检验：\u000a1、检查报废记录相关文件保存是否完整、准确。若无报废报告，可参考现场报废照片。\u000a2、检查使用过的零部件是否保存完好。'),unistr('De acuerdo con la lista de piezas usadas proporcionada por el Departamento Técnico de Reclamos, seleccione aleatoriamente 5 juegos de piezas usadas para su inspección:\u000a1. Verifique si los documentos relevantes de los registros de desechos se guardan de manera completa y precisa. Si no hay un informe de desecho, se puede consultar las fotografías de desecho en el sitio.\u000a2. Compruebe si las piezas usadas están bien conservadas.'),unistr('1、报废记录文件保存完整、准确，评分10分；保存不完整准确，给0分。\u000a2.二手零件保存完好，给10分；保存不完整准确，给0分。'),unistr('1. Los documentos de los registros de desecho se guardan de forma completa y precisa, otorgan 10 puntuaciones; No guardado de forma completa y precisa, otorga 0 puntuación.\u000a2. Las piezas usadas están bien conservadas, dé 10 puntos; No conservado de forma completa y precisa, dé 0 puntuación.'),'独家管理','Gestión Exclusiva',NULL);
INSERT INTO tqc__rules VALUES(149,'D-1-1','Multi-brand Hardware','Facade','On-site',unistr('1. Check whether there is a BYD logo on the facade of the service store, and check whether the facade is clean and aesthetically visible;\u000a2. Check whether the logo font and color of BYD Service complies with BYD''s VI design requirements.'),10,67,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with the 2 check requirements, give 10 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'正面','Fachada',unistr('1、检查服务店门面是否有比亚迪标志，并检查门面是否干净、美观；\u000a2、检查比亚迪服务标志字体、颜色是否符合比亚迪VI设计要求。'),unistr('1. Verifique si hay un logotipo de BYD en la fachada de la tienda de servicios y verifique si la fachada está limpia y estéticamente visible;\u000a2. Verifique si la fuente y el color del logotipo del Servicio BYD cumplen con los requisitos de diseño VI de BYD.'),unistr('若符合2项检查要求，则打10分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con los 2 requisitos de verificación, otorgue 10 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'多品牌硬件','Hardware multimarca',NULL);
INSERT INTO tqc__rules VALUES(150,'D-1-2','Multi-brand Hardware','Reception Area','On-site',unistr('1. Check whether there is a BYD logo in the customer reception area, and inspect the reception area background wall or reception table signage;\u000a2. Check whether the logo of BYD Service complies with BYD''s VI design requirements;\u000a3. If the customer reception area is in the show room, the BYD Service logo should also be displayed.'),10,68,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 10 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'接待区','Área de recepción',unistr('1、检查客户接待区是否有比亚迪标志，并检查接待区背景墙或接待台标识牌；\u000a2、检查比亚迪服务标志是否符合比亚迪VI设计要求；\u000a3、如果客户接待区位于展厅内，还应展示比亚迪服务标志。'),unistr('1. Verifique si hay un logotipo de BYD en el área de recepción de clientes e inspeccione la pared del fondo del área de recepción o la señalización de la mesa de recepción;\u000a2. Verificar si el logotipo del Servicio BYD cumple con los requisitos de diseño VI de BYD;\u000a3. Si el área de recepción de clientes está en la sala de exposición, también se deberá mostrar el logotipo de BYD Service.'),unistr('若符合全部检查要求，则打10分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 10 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'多品牌硬件','Hardware multimarca',NULL);
INSERT INTO tqc__rules VALUES(151,'D-1-3','Multi-brand Hardware','Workshop','On-site',unistr('The workshop VI should complies with BYD''s store construction standards, and check whether there is a BYD maintenace bay sign.\u000aNotes:\u000a1. Hang the BYD sign at the BYD maintenance bay. If the conditions for hanging are not met, it needs to be pasted on the corresponding wall of the maintenance station; it is not required to paint the exclusive bay and the lift.\u000a2. BYD maintenance bay dimensions can be flexibly adjusted according to the actual site conditions, with a width of 4±0.5m and a length of 7±1m.'),20,69,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 20 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'车间','Taller',unistr('VI车间应符合比亚迪专卖店建设标准，并检查是否有比亚迪维修间标志。\u000a注意事项：\u000a1. 在比亚迪维修车间悬挂比亚迪标志。如果不满足悬挂条件，则需要粘贴在维修站相应的墙壁上；专用海湾和电梯不需要油漆。\u000a2、比亚迪维修间尺寸可根据现场实际情况灵活调整，宽度为4±0.5m，长度为7±1m。'),unistr('El taller VI debe cumplir con los estándares de construcción de tiendas de BYD y verificar si hay un letrero en la bahía de mantenimiento de BYD.\u000aNotas:\u000a1. Cuelgue el cartel de BYD en el área de mantenimiento de BYD. Si no se cumplen las condiciones para colgarlo, es necesario pegarlo en la pared correspondiente de la estación de mantenimiento; No es necesario pintar la nave exclusiva y el ascensor.\u000a2. Las dimensiones del módulo de mantenimiento BYD se pueden ajustar de manera flexible según las condiciones reales del sitio, con un ancho de 4±0,5 my una longitud de 7±1 m.'),unistr('若符合全部检查要求，则打20分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 20 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'多品牌硬件','Hardware multimarca',NULL);
INSERT INTO tqc__rules VALUES(152,'D-1-4','Multi-brand Hardware','Workshop','On-site','Check whether BYD exclusive maintenance bay quantity ≥2.',10,70,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 10 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'车间','Taller','检查比亚迪专属维修站数量是否≥2个。','Compruebe si la cantidad del compartimento de mantenimiento exclusivo de BYD es ≥2.',unistr('若符合全部检查要求，则打10分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 10 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'多品牌硬件','Hardware multimarca',NULL);
INSERT INTO tqc__rules VALUES(153,'D-1-5','Multi-brand Hardware','Charger','On-site',unistr('Charger quantity should ≥2, respectively 1 inside and 1 outside; Power should ≥7kw;\u000a*If the chargers can only be installed inside of the service stores because of construction limimations, the total charger qty make sense.\u000a*Can be shared with other brands.'),10,71,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If comply with all the check requirements, give 10 scores;\u000aIf don''t comply with any of the check requirements, give 0 score.'),'充电器','Cargador',unistr('充电器数量≥2个，分别为1个内、1个外；功率≥7kw；\u000a*如果由于施工限制充电器只能安装在服务店内，则充电器总数量是有意义的。\u000a*可与其他品牌共享。'),unistr('La cantidad del cargador debe ser ≥2, respectivamente 1 interior y 1 exterior; La potencia debe ser ≥7kw;\u000a*Si los cargadores solo se pueden instalar dentro de las tiendas de servicio debido a limitaciones de construcción, la cantidad total de cargadores tiene sentido.\u000a*Se puede compartir con otras marcas.'),unistr('若符合全部检查要求，则打10分；\u000a如果不符合任何检查要求，则给 0 分。'),unistr('Si cumple con todos los requisitos de verificación, otorgue 10 puntajes;\u000aSi no cumple con alguno de los requisitos de verificación, otorgue 0 puntaje.'),'多品牌硬件','Hardware multimarca',NULL);
INSERT INTO tqc__rules VALUES(154,'D-1-6','Multi-brand Hardware','Service Materials','On-site',unistr('1. Check whether the service store has maintenance three-piece set, environmental friendly set of after-sales service, floor mat, delivery envelope.\u000a2. Check whether the store uses service materials in after-sales service process on-site.'),20,72,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If all types of material are found and used in on-site inspection, give 20 scores;\u000aIf one or more items are missing or not used during on-site inspection, give 0 score.'),'服务材料','Materiales de servicio',unistr('1、检查服务店是否有保养三件套、售后服务环保套装、地垫、送货信封。\u000a2、现场检查店铺在售后服务过程中是否使用服务材料。'),unistr('1. Compruebe si la tienda de servicios cuenta con un juego de mantenimiento de tres piezas, un juego de servicio posventa respetuoso con el medio ambiente, un tapete y un sobre de entrega.\u000a2. Verifique si la tienda utiliza materiales de servicio en el proceso de servicio posventa en el sitio.'),unistr('现场检查发现并使用各类材料的，打20分；\u000a现场检查时缺少或未使用一项或多项的，给予0分。'),unistr('Si se encuentran y utilizan todos los tipos de materiales en la inspección in situ, dé 20 puntos;\u000aSi uno o más elementos faltan o no se utilizan durante la inspección in situ, otorgue una puntuación de 0.'),'多品牌硬件','Hardware multimarca',NULL);
INSERT INTO tqc__rules VALUES(155,'D-2-1','Multi-brand Management','LMS Accounts for After-sales Service Store','On-site','Based on the attendance record docs and other information provided by the store, verify whether the service store has registered LMS accounts for all current employees and whether accounts have been cancelled for all resigned employees.',10,73,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If meet all requirement, give 10 scores; Otherwise, give 0 score.','售后服务店LMS账户','Cuentas LMS para tienda de servicio postventa','根据门店提供的考勤记录等信息，核实服务门店是否为所有在职员工注册了LMS账号，以及是否为所有离职员工注销了账号。','Según los documentos del registro de asistencia y otra información proporcionada por la tienda, verifique si la tienda de servicios ha registrado cuentas LMS para todos los empleados actuales y si las cuentas se han cancelado para todos los empleados renunciados.','如果满足全部要求，打10分；否则，给0分。','Si cumple con todos los requisitos, otorgue 10 puntajes; De lo contrario, dé 0 puntos.','多品牌管理','Gestión Multimarca',NULL);
INSERT INTO tqc__rules VALUES(156,'D-2-2','Multi-brand Management','Familiarity in IT System','On-site',unistr('TIS：\u000aLMS：\u000aDMS：\u000aTIS:\u000aRandomly check the operation familiarity on TIS system of one technician and one spare parts personnel.\u000a1. Technician: Randomly select a module from the EPC spare parts catalog, WSM maintenance manual, DSM diagnostic manual, WD circuit diagram, work hour query, and technical consultation, and the inspected person needs to operate it on site;\u000a2. Spare parts personnel: For the spare parts consultation module, the inspected person needs to operate on site.\u000aLMS:\u000aRandomly check the familiarity on LMS operation of two technicians, and have the inspected person operate it on site to check if they can identify the purpose of each module.\u000aDMS:\u000aFor distributor directly managed stores:\u000aRandomly check the familiarity on DMS operation of one service advisor, respectively in the material management, claim management, and maintenance management modules, have the inspected person to simulate creating the work order on site.\u000aFor stores managed by 3rd party:\u000aThe scores is the average scores of all distributor directly managed stores.'),15,74,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. TIS: If technician operates correctly, give 2.5 score; if operate wrongly, give 0 score;\u000a2. TIS: If spare parts personnel operates correctly, give 2.5 score; if operate wrongly, give 0 score;\u000a3. LMS: 1 technician can operate right, give 2.5 scores; 2 technicians can operate right, give 5 scores;\u000a4. DMS: Operate correctly, give 5 scores; if operate wrongly, give 0 score;'),'熟悉IT系统','Familiaridad en el sistema de TI.',unistr('TIS：\u000a学习管理系统：\u000a数据管理系统：\u000aTIS：\u000a抽查一名技术人员和一名备件人员对TIS系统的操作熟悉程度。\u000a1、技术人员：从EPC备件目录、WSM维修手册、DSM诊断手册、WD电路图、工时查询、技术咨询中随机选择一个模块，由受检人员现场操作；\u000a2、备件人员：对于备件咨询模块，需要被巡检人员现场操作。\u000a学习管理系统：\u000a随机检查两名技术人员对LMS操作的熟悉程度，并让被检查人员现场操作，检查是否能识别各模块的用途。\u000a数据管理系统：\u000a对于经销商直营店：\u000a随机检查一名服务顾问对DMS操作的熟悉程度，分别在物料管理、索赔管理、维修管理模块，让被检查人员现场模拟创建工单。\u000a对于第三方管理的商店：\u000a分数为所有经销商直营店的平均分。'),unistr('TIS:\u000aLMS:\u000aDMS:\u000aTIS:\u000aVerifique aleatoriamente la familiaridad con la operación del sistema TIS de un técnico y un personal de repuestos.\u000a1. Técnico: seleccione aleatoriamente un módulo del catálogo de repuestos de EPC, manual de mantenimiento de WSM, manual de diagnóstico de DSM, diagrama de circuito de WD, consulta de horas de trabajo y consulta técnica, y la persona inspeccionada debe operarlo en el sitio;\u000a2. Personal de repuestos: Para el módulo de consulta de repuestos, la persona inspeccionada debe operar en el sitio.\u000aLMS:\u000aVerifique aleatoriamente la familiaridad de dos técnicos con el funcionamiento del LMS y haga que la persona inspeccionada lo opere en el sitio para verificar si puede identificar el propósito de cada módulo.\u000aDMS:\u000aPara tiendas administradas directamente por el distribuidor:\u000aVerifique aleatoriamente la familiaridad con el funcionamiento del DMS de un asesor de servicio, respectivamente en los módulos de gestión de materiales, gestión de reclamos y gestión de mantenimiento, y haga que la persona inspeccionada simule la creación de la orden de trabajo en el sitio.\u000aPara tiendas administradas por terceros:\u000aLas puntuaciones son las puntuaciones medias de todas las tiendas gestionadas directamente por los distribuidores.'),unistr('1. TIS：技术人员操作正确，打2.5分；如果操作错误，给0分；\u000a2、TIS：备件人员操作正确，打2.5分；如果操作错误，给0分；\u000a3. LMS：1名技术人员能够正确操作，给予2.5分； 2名技术人员操作正确，给5分；\u000a4、DMS：操作正确，给5分；如果操作错误，给0分；'),unistr('1. TIS: Si el técnico opera correctamente, otorgue una puntuación de 2,5; si funciona incorrectamente, dé 0 puntuación;\u000a2. TIS: Si el personal de repuestos opera correctamente, otorgar puntuación de 2,5; si funciona incorrectamente, dé 0 puntuación;\u000a3. LMS: 1 técnico puede operar correctamente, otorga 2,5 puntajes; 2 técnicos pueden operar correctamente, otorgar 5 puntajes;\u000a4. DMS: opere correctamente, otorgue 5 puntajes; si funciona incorrectamente, dé 0 puntuación;'),'多品牌管理','Gestión Multimarca',NULL);
INSERT INTO tqc__rules VALUES(157,'D-2-3','Multi-brand Management','DMS work order Input','On-site','Verify that the DMS contains non-claim repair orders, and that the number of non-claim repair orders integrated into or recorded in the DMS accounts for at least 80% of the number of non-claim repair orders in the distributor''s own system.',15,75,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If the proportion of the number of work orders entered in DMS to the number of non - claim work orders in the proprietary system is ≥ 80%, give 15 scores; otherwise, give 0 score.','DMS工单输入','Entrada de orden de trabajo de DMS','验证 DMS 中是否包含无索赔维修订单，并且集成或记录在 DMS 中的无索赔维修订单数量至少占经销商自身系统中无索赔维修订单数量的 80%。','Verifique que el DMS contenga órdenes de reparación sin reclamo y que el número de órdenes de reparación sin reclamo integradas o registradas en el DMS represente al menos el 80% del número de órdenes de reparación sin reclamo en el propio sistema del distribuidor.','若DMS录入工单数量与专有系统中非索赔工单数量比例≥80%，则打15分；否则，给0分。','Si la proporción del número de órdenes de trabajo ingresadas en DMS con respecto al número de órdenes de trabajo sin reclamo en el sistema propietario es ≥ 80%, otorgue 15 puntajes; de lo contrario, dé 0 puntuación.','多品牌管理','Gestión Multimarca',NULL);
INSERT INTO tqc__rules VALUES(158,'D-2-4','Multi-brand Management','Service Appointment Waiting Time','On-site',unistr('On-site verification of service appointment waiting time may be conducted through WhatsApp, telephone records, or dealer systems\u000a(including review of WhatsApp chat records and detailed call / system records).\u000a\u000aService appointment waiting time =\u000aEarliest appointment date offered by the dealer − Customer’s requested appointment date.\u000a\u000aIf the customer’s requested appointment date is not clearly recorded,\u000athe customer’s requested date shall be deemed as the date when the appointment was made.'),10,76,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. If all 3 maintenance/repair orders have an appointment waiting time within 5 days, give 10 scores.\u000a2. If 2 maintenance/repair orders have an appointment waiting time within 5 days, give 5 scores.\u000a3. If fewer than 2 maintenance/repair orders have an appointment waiting time within 5 days, give 0 score.'),'服务预约等候时间','Tiempo de espera de cita de servicio',unistr('现场核实服务预约等待时间可通过WhatsApp、电话记录或经销商系统进行\u000a（包括查看WhatsApp聊天记录和详细通话/系统记录）。\u000a\u000a服务预约等待时间=\u000a经销商提供的最早预约日期 - 客户要求的预约日期。\u000a\u000a如果客户要求的预约日期没有明确记录，\u000a客户要求的日期将被视为预约日期。'),unistr('La verificación in situ del tiempo de espera de la cita de servicio se puede realizar a través de WhatsApp, registros telefónicos o sistemas del distribuidor.\u000a(incluida la revisión de los registros de chat de WhatsApp y los registros detallados de llamadas/sistema).\u000a\u000aTiempo de espera de cita de servicio =\u000aFecha de cita más temprana ofrecida por el distribuidor: fecha de cita solicitada por el cliente.\u000a\u000aSi la fecha de la cita solicitada por el cliente no está claramente registrada,\u000aLa fecha solicitada por el cliente se considerará como la fecha en la que se realizó la cita.'),unistr('1. 如果3个保养/维修订单都有5天内的预约等待时间，则打10分。\u000a2. 如果有2个维护/维修订单的预约等待时间在5天内，则给5分。\u000a3. 如果5天内有预约等待时间的维护/维修订单少于2个，则给予0分。'),unistr('1. Si las 3 órdenes de mantenimiento/reparación tienen un tiempo de espera de cita dentro de los 5 días, otorgue 10 puntos.\u000a2. Si 2 órdenes de mantenimiento/reparación tienen un tiempo de espera de cita dentro de los 5 días, dé 5 puntos.\u000a3. Si menos de 2 órdenes de mantenimiento/reparación tienen un tiempo de espera de cita dentro de los 5 días, otorgue 0 puntaje.'),'多品牌管理','Gestión Multimarca',NULL);
INSERT INTO tqc__rules VALUES(159,'D-2-5','Multi-brand Management','Inventory Management','On-site','Randomly inspect 10 types of spare parts to check if the physical quantity matches the actual inventory quantity in the inventory management system (Spare parts of type A&B must be checked).',10,77,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13','If the total gap quantity of the 10 types is ≤ 2, give 10 score; If gap quantity ＞2, give 0 score.','库存管理','Gestión de inventario','随机抽查10种备件，检查实物数量与库存管理系统中的实际库存数量是否相符（A、B类备件必须检查）。','Inspeccione aleatoriamente 10 tipos de repuestos para verificar si la cantidad física coincide con la cantidad real del inventario en el sistema de gestión de inventario (se deben verificar los repuestos de tipo A y B).','如果10种类型的缺口总数≤2，则给10分；如果差距数量＞2，则给0分。','Si la cantidad total de espacios de los 10 tipos es ≤ 2, dé 10 puntos; Si la cantidad de espacio es >2, dé 0 puntuación.','多品牌管理','Gestión Multimarca',NULL);
INSERT INTO tqc__rules VALUES(160,'D-2-6','Multi-brand Management','Fulfill rate of Regularly Prepared Spare Parts','On-site',unistr('According to BYD Spare Parts Recommendation List, check whether the recommended spare parts in the inventory management system meet the type requirements in the recommended spare parts list.\u000aFulfill rate=Number of recommended spare parts in stock in the store inventory management system/Number of spare parts in the recommended spare parts list * 100%.'),10,78,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Fulfill rate is [90%, 100%], give 10 scores.\u000a2. Fulfill rate is [75%, 90%), give 7 scores.\u000a3. Fulfill rate is [60%, 75%), give 4 scores.\u000a4. Fulfill rate is [0, 60%), give 0 score.'),'定期备件履行率','Tasa de cumplimiento de repuestos preparados periódicamente',unistr('根据比亚迪备件推荐清单，检查库存管理系统中的推荐备件是否符合推荐备件清单中的型号要求。\u000a履行率=门店库存管理系统库存推荐备件数量/推荐备件清单备件数量*100%。'),unistr('De acuerdo con la Lista de recomendaciones de repuestos de BYD, verifique si los repuestos recomendados en el sistema de gestión de inventario cumplen con los requisitos de tipo en la lista de repuestos recomendados.\u000aTasa de cumplimiento = Número de repuestos recomendados en stock en el sistema de gestión de inventario de la tienda/Número de repuestos en la lista de repuestos recomendados * 100%.'),unistr('1. 完成率为[90%, 100%]，给10分。\u000a2. 完成率为[75%, 90%)，给7分。\u000a3. 完成率为[60%, 75%)，打4分。\u000a4. 完成率为[0, 60%)，给0分。'),unistr('1. La tasa de cumplimiento es [90%, 100%], otorga 10 puntajes.\u000a2. La tasa de cumplimiento es [75%, 90%), otorga 7 puntajes.\u000a3. La tasa de cumplimiento es [60%, 75%), dé 4 puntajes.\u000a4. La tasa de cumplimiento es [0, 60%), otorga 0 puntuación.'),'多品牌管理','Gestión Multimarca',NULL);
INSERT INTO tqc__rules VALUES(161,'D-2-7','Multi-brand Management','Q&A-Technical Skills','On-site','Randomly select 5 technical related questions from the trainning exams bank and have 1 technician to answer them.',10,79,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Answer correctly 5 questions, give 10 scores;\u000a2. Answer correctly 4 questions, give 5 scores;\u000a3. Answer correctly 3 questions or less, give 0 score.'),'问答-技术技能','Preguntas y respuestas: habilidades técnicas','从培训考试库中随机抽取 5 道技术相关问题，并由 1 名技术人员进行解答。','Seleccione aleatoriamente 5 preguntas técnicas relacionadas del banco de exámenes de capacitación y haga que 1 técnico las responda.',unistr('1.正确回答5题，给出10分；\u000a2.正确回答4题，给出5分；\u000a3.答对3题或以下，给0分。'),unistr('1. Responda correctamente 5 preguntas, dé 10 puntuaciones;\u000a2. Responda correctamente 4 preguntas, dé 5 puntuaciones;\u000a3. Responda correctamente 3 preguntas o menos, dé 0 puntuación.'),'多品牌管理','Gestión Multimarca',NULL);
INSERT INTO tqc__rules VALUES(162,'D-2-8','Multi-brand Management','6S Management','On-site','Check whether the management of after-sales stores meets the requirements of 6S management standards.',20,80,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('If meet the requirement, give 20 scores;\u000aOtherwise, give 0 score.'),'6S管理','Gestión 6S','检查售后店管理是否符合6S管理标准要求。','Compruebe si la gestión de las tiendas de posventa cumple con los requisitos de los estándares de gestión 6S.',unistr('符合要求的，打20分；\u000a否则，给0分。'),unistr('Si cumple con el requisito, otorgue 20 puntajes;\u000aDe lo contrario, dé 0 puntos.'),'多品牌管理','Gestión Multimarca',NULL);
INSERT INTO tqc__rules VALUES(163,'D-2-9','Multi-brand Management','Claim Parts Storage Management','On-site',unistr('According to the list of used parts provided by the Technical Claims Department, randomly select 5 sets of used parts for inspection:\u000a1. Check whether the relevant documents of the scrap records are saved completely and accurately. If there is no scrap report, the on-site scrap photos can be referred to.\u000a2. Check whether the used parts are well preserved.'),10,81,'2026 Q2 Quarterly TQC','2026-06-17 14:25:06','2026-06-20 16:51:13',unistr('1. Documents of the scrap records are saved completely and accurately, give 5 scores; Not saved completely and accurately, give 0 score.\u000a2. used parts are well preserved, give 5 scores; Not preserved completely and accurately, give 0 score.'),'索赔零件存储管理','Gestión de almacenamiento de piezas de reclamación',unistr('根据技术索赔部提供的旧件清单，随机抽取5套旧件进行检验：\u000a1、检查报废记录相关文件保存是否完整、准确。若无报废报告，可参考现场报废照片。\u000a2、检查使用过的零部件是否保存完好。'),unistr('De acuerdo con la lista de piezas usadas proporcionada por el Departamento Técnico de Reclamos, seleccione aleatoriamente 5 juegos de piezas usadas para su inspección:\u000a1. Verifique si los documentos relevantes de los registros de desechos se guardan de manera completa y precisa. Si no hay un informe de desecho, se puede consultar las fotografías de desecho en el sitio.\u000a2. Compruebe si las piezas usadas están bien conservadas.'),unistr('1、报废记录文件保存完整、准确，5分；保存不完整准确，给0分。\u000a2.使用过的部件保存完好，给5分；保存不完整准确，给0分。'),unistr('1. Los documentos de los registros de desecho se guardan de forma completa y precisa, otorga 5 puntuaciones; No guardado de forma completa y precisa, otorga 0 puntuación.\u000a2. las piezas usadas están bien conservadas, dé 5 puntos; No conservado de forma completa y precisa, dé 0 puntuación.'),'多品牌管理','Gestión Multimarca',NULL);
