PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE tqc__rules (
            id            INTEGER PRIMARY KEY AUTOINCREMENT,
            sn            TEXT NOT NULL,
            category      TEXT,
            inspection_item  TEXT NOT NULL,
            inspection_way   TEXT NOT NULL,
            inspection_standard TEXT,
            max_score     INTEGER DEFAULT 100,
            sort_order    INTEGER DEFAULT 0,
            sheet_name    TEXT NOT NULL,
            created_at    TEXT DEFAULT (datetime('now')),
            updated_at    TEXT DEFAULT (datetime('now')), rating_explanation TEXT, inspection_item_zh TEXT, inspection_item_es TEXT, inspection_standard_zh TEXT, inspection_standard_es TEXT, rating_explanation_zh TEXT, rating_explanation_es TEXT, category_zh TEXT, category_es TEXT, inspection_way_zh TEXT,
            UNIQUE(sn, sheet_name)
        );
COMMIT;
